-- ============================================================
-- Quiz Seed: Psalms Chapters 1–30
-- Target table: chapter_quizzes
-- Difficulties: kids (3 Qs), teens (5 Qs), adults (8 Qs)
-- ============================================================

-- ═══════════════════════════════════════════
-- CHAPTERS 1 – 10
-- ═══════════════════════════════════════════

-- ═══ Psalms Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 1, 'kids', 1, 'What is the blessed man compared to in Psalm 1?', 'A tree planted by rivers of water', 'A bird flying in the sky', 'A rock on a hill', 'A flower in a field', 'a', 'The blessed man is like a tree planted by the rivers of water (Psalm 1:3).'),
('Psalms', 1, 'kids', 2, 'What does the ungodly man blow away like?', 'Leaves', 'Dust', 'Chaff', 'Sand', 'a', 'The ungodly are like the chaff which the wind driveth away (Psalm 1:4).'),
('Psalms', 1, 'kids', 3, 'What does the blessed man delight in?', 'The law of the LORD', 'His own wisdom', 'Earthly riches', 'The counsel of friends', 'a', 'His delight is in the law of the LORD; and in his law doth he meditate day and night (Psalm 1:2).'),
-- Teens
('Psalms', 1, 'teens', 1, 'What three things does the blessed man NOT do according to Psalm 1:1?', 'Sing, dance, or play', 'Walk in the counsel of the ungodly, stand in the way of sinners, or sit in the seat of the scornful', 'Eat, sleep, or rest', 'Fight, steal, or lie', 'a', 'Blessed is the man that walketh not in the counsel of the ungodly, nor standeth in the way of sinners, nor sitteth in the seat of the scornful (Psalm 1:1).'),
('Psalms', 1, 'teens', 2, 'When does the blessed man meditate on the law of the LORD?', 'Only on the Sabbath', 'Only in the morning', 'Day and night', 'Once a week', 'a', 'In his law doth he meditate day and night (Psalm 1:2).'),
('Psalms', 1, 'teens', 3, 'What does the tree by rivers of water bring forth in its season?', 'Its fruit', 'Its flowers', 'Its shade', 'Its roots', 'a', 'He shall be like a tree...that bringeth forth his fruit in his season (Psalm 1:3).'),
('Psalms', 1, 'teens', 4, 'What shall the ungodly not do?', 'Stand in the judgment', 'Enter the temple', 'See the LORD', 'Receive mercy', 'a', 'The ungodly shall not stand in the judgment (Psalm 1:5).'),
('Psalms', 1, 'teens', 5, 'What does Psalm 1 say about the way of the ungodly?', 'It leads to riches', 'It shall perish', 'It shall continue', 'It is hidden', 'a', 'The way of the ungodly shall perish (Psalm 1:6).'),
-- Adults
('Psalms', 1, 'adults', 1, 'What is the Hebrew word translated "blessed" in Psalm 1:1 and what does it convey?', 'Shalom — peace', 'Asher — a state of deep happiness and wellbeing', 'Baruch — divine blessing', 'Halal — praise', 'a', 'The Hebrew word is ''Ashre (from asher), conveying a state of genuine happiness and wellbeing, often translated "how happy is the man."'),
('Psalms', 1, 'adults', 2, 'What does the leaf of the righteous man''s tree not do, according to Psalm 1:3?', 'Fall into water', 'Wither', 'Grow too large', 'Change colour', 'a', 'His leaf also shall not wither; and whatsoever he doeth shall prosper (Psalm 1:3).'),
('Psalms', 1, 'adults', 3, 'What knowledge does the LORD have regarding the way of the righteous?', 'He overlooks it', 'He knoweth it', 'He judges it', 'He tests it', 'a', 'The LORD knoweth the way of the righteous: but the way of the ungodly shall perish (Psalm 1:6).'),
('Psalms', 1, 'adults', 4, 'The congregation of the righteous is contrasted with what group in Psalm 1:5?', 'The sinners', 'The ungodly', 'The proud', 'The wicked rulers', 'a', 'Nor sinners in the congregation of the righteous (Psalm 1:5).'),
('Psalms', 1, 'adults', 5, 'What structural feature of Psalm 1 makes it an ideal introduction to the entire Psalter?', 'It is the longest psalm', 'It sets forth the two ways — the way of the righteous and the way of the ungodly — as a framework for the whole book', 'It mentions David by name', 'It is a lament psalm', 'a', 'Psalm 1 presents the "two ways" — righteous vs. ungodly — serving as a gateway and introduction to the entire book of Psalms.'),
('Psalms', 1, 'adults', 6, 'What does the image of the tree by rivers of water emphasize about the righteous man?', 'His wealth', 'His constant nourishment from God''s word leading to fruitfulness and stability', 'His physical strength', 'His social influence', 'a', 'The tree planted by rivers of water bringeth forth his fruit in his season; his leaf also shall not wither (Psalm 1:3).'),
('Psalms', 1, 'adults', 7, 'What does it mean that the blessed man meditates on the law "day and night"?', 'He reads the scroll literally all day', 'He is continuously and deeply engaged with God''s word in all of life', 'He memorizes every verse', 'He reads only morning and evening prayers', 'a', 'Day and night meditation reflects a life permeated by the word of God, not merely formal study (Psalm 1:2).'),
('Psalms', 1, 'adults', 8, 'How does Psalm 1 contrast the ultimate fate of the righteous versus the ungodly?', 'The righteous suffer more but are eventually rewarded', 'The LORD knoweth the way of the righteous, but the way of the ungodly shall perish', 'Both face judgment equally', 'The ungodly prosper in this life only', 'a', 'The LORD knoweth the way of the righteous: but the way of the ungodly shall perish (Psalm 1:6).');

-- ═══ Psalms Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 2, 'kids', 1, 'Who does God call His Son in Psalm 2?', 'The Messiah King', 'The angel of heaven', 'King David only', 'The prophet', 'a', 'God declares, "Thou art my Son; this day have I begotten thee" (Psalm 2:7).'),
('Psalms', 2, 'kids', 2, 'What are the kings of the earth doing in Psalm 2?', 'Worshipping God', 'Raging against God and His anointed', 'Building great temples', 'Fighting each other', 'a', 'The kings of the earth set themselves, and the rulers take counsel together, against the LORD (Psalm 2:2).'),
('Psalms', 2, 'kids', 3, 'What does the psalm say we should do to the Son?', 'Kiss the Son', 'Obey the Son', 'Fear the Son', 'Follow the Son', 'a', 'Kiss the Son, lest he be angry, and ye perish from the way (Psalm 2:12).'),
-- Teens
('Psalms', 2, 'teens', 1, 'What do the rulers plot to break in Psalm 2:3?', 'The temple walls', 'Their bands and cords — God''s rule over them', 'The ark of the covenant', 'The sacred scrolls', 'a', 'Let us break their bands asunder, and cast away their cords from us (Psalm 2:3).'),
('Psalms', 2, 'teens', 2, 'How does God respond to the raging nations?', 'He sends angels to fight', 'He laughs and holds them in derision', 'He destroys them immediately', 'He ignores them', 'a', 'He that sitteth in the heavens shall laugh: the LORD shall have them in derision (Psalm 2:4).'),
('Psalms', 2, 'teens', 3, 'What does God promise to give the Son as His inheritance?', 'The temple of Jerusalem', 'The heathen and the uttermost parts of the earth', 'All of Israel''s land', 'The treasures of heaven', 'a', 'Ask of me, and I shall give thee the heathen for thine inheritance, and the uttermost parts of the earth for thy possession (Psalm 2:8).'),
('Psalms', 2, 'teens', 4, 'With what does the Son rule the nations?', 'A golden sceptre', 'A rod of iron', 'A sword of fire', 'A staff of wood', 'a', 'Thou shalt break them with a rod of iron; thou shalt dash them in pieces like a potter''s vessel (Psalm 2:9).'),
('Psalms', 2, 'teens', 5, 'What advice does Psalm 2 give to kings and judges?', 'Be wise, be instructed, serve the LORD with fear', 'Build strong armies', 'Make peace with all nations', 'Trust in your own strength', 'a', 'Be wise now therefore, O ye kings: be instructed, ye judges of the earth. Serve the LORD with fear (Psalm 2:10-11).'),
-- Adults
('Psalms', 2, 'adults', 1, 'In what New Testament passage is Psalm 2:7 quoted regarding Jesus'' resurrection?', 'John 3:16', 'Acts 13:33', 'Romans 8:1', 'Hebrews 12:2', 'a', 'Paul quotes Psalm 2:7 in Acts 13:33 — "Thou art my Son, this day have I begotten thee" — applied to the resurrection of Jesus.'),
('Psalms', 2, 'adults', 2, 'What is the Hebrew word translated "anointed" in Psalm 2:2, and what is its significance?', 'Elohim — God', 'Mashiach — the word from which "Messiah" derives', 'Adonai — Lord', 'Ruach — Spirit', 'a', 'The Hebrew word is Mashiach (anointed one), from which the English word Messiah is directly derived (Psalm 2:2).'),
('Psalms', 2, 'adults', 3, 'Where does God say He has set His King in Psalm 2:6?', 'In the heavenly throne room', 'Upon my holy hill of Zion', 'In the tabernacle of the congregation', 'Upon the throne of David in Jerusalem', 'a', 'Yet have I set my king upon my holy hill of Zion (Psalm 2:6).'),
('Psalms', 2, 'adults', 4, 'What does "Blessed are all they that put their trust in him" in Psalm 2:12 echo?', 'The call of Abraham', 'The opening beatitude of Psalm 1 — linking the two psalms as a unified introduction', 'The commandments of Moses', 'The prophecy of Isaiah', 'a', 'Psalm 2:12 closes with "blessed," echoing Psalm 1:1, binding these two psalms together as a double introduction to the Psalter.'),
('Psalms', 2, 'adults', 5, 'What does the image of dashing nations "like a potter''s vessel" in Psalm 2:9 communicate?', 'Gentle correction', 'Absolute, irreversible judgment with total authority', 'A gradual process of discipline', 'God''s regret over nations', 'a', 'Thou shalt dash them in pieces like a potter''s vessel (Psalm 2:9), depicting irresistible, complete judgment.'),
('Psalms', 2, 'adults', 6, 'How is Psalm 2 classified by most biblical scholars?', 'A lament psalm', 'A royal or Messianic psalm', 'A wisdom psalm', 'A psalm of ascent', 'a', 'Psalm 2 is classified as a royal/Messianic psalm, finding its ultimate fulfillment in Jesus Christ as the anointed Son.'),
('Psalms', 2, 'adults', 7, 'What does it mean to "kiss the Son" in Psalm 2:12?', 'A physical sign of greeting', 'An act of homage and submission acknowledging his sovereignty', 'A ritual of worship in the temple', 'A sign of friendship', 'a', 'Kiss the Son — the kiss was an ancient Near Eastern sign of submission and homage to a king (Psalm 2:12).'),
('Psalms', 2, 'adults', 8, 'In what way does Revelation 2:27 and 19:15 connect to Psalm 2?', 'They both describe creation', 'Both apply the rod of iron rule from Psalm 2:9 to the risen and reigning Christ', 'They describe the flood', 'They repeat the exodus story', 'a', 'Revelation 2:27 and 19:15 directly quote Psalm 2:9, applying the Messianic rod of iron rule to the glorified Christ.');

-- ═══ Psalms Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 3, 'kids', 1, 'Who ran away from David, causing him to write Psalm 3?', 'His enemy Goliath', 'His son Absalom', 'King Saul', 'The Philistines', 'a', 'The title of Psalm 3 reads: "A Psalm of David, when he fled from Absalom his son."'),
('Psalms', 3, 'kids', 2, 'What does David call God in Psalm 3:3?', 'A shield for me', 'A tower of strength', 'A mighty warrior', 'A bright light', 'a', 'But thou, O LORD, art a shield for me; my glory, and the lifter up of mine head (Psalm 3:3).'),
('Psalms', 3, 'kids', 3, 'What did David do and not be afraid of?', 'He lay down and slept', 'He prayed all night', 'He ran into battle', 'He climbed a mountain', 'a', 'I laid me down and slept; I awaked; for the LORD sustained me. I will not be afraid (Psalm 3:5-6).'),
-- Teens
('Psalms', 3, 'teens', 1, 'What do many say about David''s situation in Psalm 3:2?', 'That God is with him', 'There is no help for him in God', 'That he will win the battle', 'That he should surrender', 'a', 'Many there be which say of my soul, There is no help for him in God (Psalm 3:2).'),
('Psalms', 3, 'teens', 2, 'What three things does David say God is to him in Psalm 3:3?', 'My rock, my fortress, my deliverer', 'A shield, my glory, and the lifter up of mine head', 'My shepherd, my light, my salvation', 'My strength, my song, my hope', 'a', 'Thou, O LORD, art a shield for me; my glory, and the lifter up of mine head (Psalm 3:3).'),
('Psalms', 3, 'teens', 3, 'From where did God answer David?', 'From the tabernacle', 'Out of his holy hill', 'From a cloud', 'From Jerusalem', 'a', 'I cried unto the LORD with my voice, and he heard me out of his holy hill (Psalm 3:4).'),
('Psalms', 3, 'teens', 4, 'How many of David''s enemies stood against him?', 'A few dozen', 'Tens of thousands of people', 'An army of thousands', 'A hundred men', 'a', 'I will not be afraid of ten thousands of people, that have set themselves against me round about (Psalm 3:6).'),
('Psalms', 3, 'teens', 5, 'What does David ask God to do to his enemies'' teeth?', 'Break them', 'Make them dull', 'Close their mouths', 'Remove them', 'a', 'Arise, O LORD; save me, O my God: for thou hast smitten all mine enemies upon the cheek bone; thou hast broken the teeth of the ungodly (Psalm 3:7).'),
-- Adults
('Psalms', 3, 'adults', 1, 'What is the historical context given in the superscription of Psalm 3?', 'David''s flight from Saul in the wilderness', 'David''s flight from Absalom his son (2 Samuel 15)', 'David''s victory over the Philistines', 'David''s sin with Bathsheba', 'a', 'The superscription reads: "A Psalm of David, when he fled from Absalom his son," referring to 2 Samuel 15.'),
('Psalms', 3, 'adults', 2, 'What does the word "Selah" appearing in Psalm 3 most likely indicate?', 'A pause for silent reflection or a musical interlude', 'The end of the psalm', 'A command to the reader', 'A Hebrew word for praise', 'a', 'Selah appears three times in Psalm 3; it is a musical or liturgical term likely indicating a pause or interlude for reflection.'),
('Psalms', 3, 'adults', 3, 'What does David''s ability to sleep amid ten thousands of enemies reveal about his faith?', 'He was exhausted from battle', 'He trusted so completely in God''s protection that fear did not prevent rest', 'He did not know the danger', 'He had guards watching over him', 'a', 'I laid me down and slept; I awaked; for the LORD sustained me (Psalm 3:5) — sleep in crisis is a sign of deep trust in God.'),
('Psalms', 3, 'adults', 4, 'Where does salvation belong according to Psalm 3:8?', 'To the king''s army', 'Unto the LORD', 'To the righteous man', 'To the people of Israel', 'a', 'Salvation belongeth unto the LORD: thy blessing is upon thy people (Psalm 3:8).'),
('Psalms', 3, 'adults', 5, 'What does the phrase "lifter up of mine head" in Psalm 3:3 signify?', 'Physical strength', 'Restoration of dignity and honor in the midst of shame', 'God''s physical presence', 'A crown being placed', 'a', 'Thou art...the lifter up of mine head (Psalm 3:3) — in ancient Near Eastern culture, a bowed head signified shame; God restores David''s dignity.'),
('Psalms', 3, 'adults', 6, 'What petition does David make in Psalm 3:7 using two imperatives?', 'Listen and act', 'Arise, O LORD; save me, O my God', 'Come down and fight', 'Hear me and answer', 'a', 'Arise, O LORD; save me, O my God (Psalm 3:7) — two urgent imperatives calling God to rise and rescue.'),
('Psalms', 3, 'adults', 7, 'How does Psalm 3 model the movement from lament to confidence found throughout the Psalter?', 'It begins with joy and ends with sorrow', 'It moves from describing overwhelming enemies (vv. 1-2) through trust in God (vv. 3-6) to bold petition and assurance (vv. 7-8)', 'It has no movement — it is entirely praise', 'It starts and ends with the same complaint', 'a', 'Psalm 3 follows the classic lament pattern: complaint (1-2), confession of trust (3-6), petition (7), and affirmation of salvation (8).'),
('Psalms', 3, 'adults', 8, 'What blessing does David extend at the close of Psalm 3?', 'Blessing on the king of Israel', 'Thy blessing is upon thy people', 'Peace to Jerusalem forever', 'Grace to the house of David', 'a', 'Salvation belongeth unto the LORD: thy blessing is upon thy people (Psalm 3:8).');

-- ═══ Psalms Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 4, 'kids', 1, 'When did David write this prayer — morning or evening?', 'Evening', 'Morning', 'At noon', 'At midnight', 'a', 'Psalm 4 is an evening prayer — David says, "I will both lay me down in peace, and sleep" (Psalm 4:8).'),
('Psalms', 4, 'kids', 2, 'What does David say God has done when he called to Him?', 'Enlarged me', 'Ignored him', 'Sent angels', 'Given him gold', 'a', 'Thou hast enlarged me when I was in distress (Psalm 4:1).'),
('Psalms', 4, 'kids', 3, 'With what does David say he will lie down and sleep?', 'Peace', 'Joy', 'Wealth', 'Strength', 'a', 'I will both lay me down in peace, and sleep: for thou, LORD, only makest me dwell in safety (Psalm 4:8).'),
-- Teens
('Psalms', 4, 'teens', 1, 'What does David call those who love vanity and seek leasing in Psalm 4:2?', 'Sons of God', 'Sons of men', 'Sons of the wicked', 'Sons of darkness', 'a', 'O ye sons of men, how long will ye turn my glory into shame? how long will ye love vanity, and seek after leasing? (Psalm 4:2).'),
('Psalms', 4, 'teens', 2, 'What does David say about those who are godly — what has God set them apart for?', 'For suffering', 'The LORD hath set apart him that is godly for himself', 'For leadership only', 'For the temple service', 'a', 'Know that the LORD hath set apart him that is godly for himself: the LORD will hear when I call unto him (Psalm 4:3).'),
('Psalms', 4, 'teens', 3, 'What does David instruct people to do on their beds?', 'Stand in awe and sin not; commune with your own heart and be still', 'Pray long prayers', 'Fast and weep', 'Read the law', 'a', 'Stand in awe, and sin not: commune with your own heart upon your bed, and be still (Psalm 4:4).'),
('Psalms', 4, 'teens', 4, 'What kind of sacrifices does David tell the people to offer?', 'Burnt offerings', 'Sacrifices of righteousness', 'Peace offerings', 'Sin offerings', 'a', 'Offer the sacrifices of righteousness, and put your trust in the LORD (Psalm 4:5).'),
('Psalms', 4, 'teens', 5, 'What does God''s countenance lifting up put in David''s heart?', 'Gladness', 'Wisdom', 'Courage', 'Strength', 'a', 'Thou hast put gladness in my heart, more than in the time that their corn and their wine increased (Psalm 4:7).'),
-- Adults
('Psalms', 4, 'adults', 1, 'To whom does David address the opening of Psalm 4, and what title does he use?', 'To the people of Israel', 'To God of my righteousness', 'To the LORD of hosts', 'To the God of Abraham', 'a', 'Hear me when I call, O God of my righteousness (Psalm 4:1) — David appeals to God as the one who vindicates the righteous.'),
('Psalms', 4, 'adults', 2, 'What New Testament epistle quotes the command "Be ye angry, and sin not" from Psalm 4:4?', 'Romans', 'Ephesians 4:26', '1 Corinthians', 'Colossians', 'a', 'Paul quotes Psalm 4:4 in Ephesians 4:26 — "Be ye angry, and sin not: let not the sun go down upon your wrath."'),
('Psalms', 4, 'adults', 3, 'What agricultural imagery does David use to describe others'' prosperity in Psalm 4:7?', 'Their flocks and herds multiplying', 'The time that their corn and their wine increased', 'Their fields yielding great harvests', 'Their olive trees producing oil', 'a', 'Thou hast put gladness in my heart, more than in the time that their corn and their wine increased (Psalm 4:7).'),
('Psalms', 4, 'adults', 4, 'What is the theological significance of David sleeping peacefully in Psalm 4:8?', 'He was physically exhausted', 'It demonstrates that true security is found in God alone, not in material wealth or military strength', 'He had no enemies at that time', 'He was at peace after a military victory', 'a', 'I will both lay me down in peace, and sleep: for thou, LORD, only makest me dwell in safety (Psalm 4:8) — safety is in God alone.'),
('Psalms', 4, 'adults', 5, 'What does "leasing" mean in Psalm 4:2?', 'Property rental', 'Falsehood or lies', 'Vanity', 'Idols', 'a', '"How long will ye love vanity, and seek after leasing?" (Psalm 4:2) — "leasing" is an archaic KJV word meaning falsehood or lies.'),
('Psalms', 4, 'adults', 6, 'Many ask "Who will shew us any good?" in Psalm 4:6. What is David''s answer?', 'A righteous king', 'LORD, lift thou up the light of thy countenance upon us', 'A prophet''s word', 'An abundant harvest', 'a', 'LORD, lift thou up the light of thy countenance upon us (Psalm 4:6) — God''s face shining on us is the true good.'),
('Psalms', 4, 'adults', 7, 'The instruction to "be still" on the bed in Psalm 4:4 anticipates what similar command in Psalms?', 'Psalm 23:2', 'Psalm 46:10 — "Be still, and know that I am God"', 'Psalm 91:1', 'Psalm 37:7', 'a', 'The call to silent stillness in Psalm 4:4 anticipates "Be still, and know that I am God" in Psalm 46:10.'),
('Psalms', 4, 'adults', 8, 'What does David''s contrast between gladness from God and gladness from corn and wine teach?', 'That agriculture is sinful', 'That spiritual joy from God''s favour surpasses any material prosperity', 'That fasting is required for joy', 'That wine is forbidden', 'a', 'Thou hast put gladness in my heart, more than in the time that their corn and their wine increased (Psalm 4:7) — God''s joy exceeds material abundance.');

-- ═══ Psalms Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 5, 'kids', 1, 'When does David pray to God in Psalm 5?', 'In the morning', 'At night', 'At noon', 'In the evening', 'a', 'My voice shalt thou hear in the morning, O LORD; in the morning will I direct my prayer unto thee (Psalm 5:3).'),
('Psalms', 5, 'kids', 2, 'Where does David want God to lead him?', 'In thy righteousness', 'To the promised land', 'To the holy mountain', 'Into battle', 'a', 'Lead me, O LORD, in thy righteousness because of mine enemies; make thy way straight before my face (Psalm 5:8).'),
('Psalms', 5, 'kids', 3, 'What does David say those who love God''s name will do?', 'Shout for joy', 'Be safe forever', 'Receive riches', 'Win every battle', 'a', 'Let all those that put their trust in thee rejoice: let them ever shout for joy (Psalm 5:11).'),
-- Teens
('Psalms', 5, 'teens', 1, 'What does David say about those who love God''s name at the end of Psalm 5?', 'They will rule nations', 'Thou shalt bless the righteous; with favour wilt thou compass him as with a shield', 'They will live in the temple', 'They will receive great wealth', 'a', 'Thou, LORD, wilt bless the righteous; with favour wilt thou compass him as with a shield (Psalm 5:12).'),
('Psalms', 5, 'teens', 2, 'What does David say God is NOT a God who?', 'Forgets the poor', 'Has pleasure in wickedness', 'Answers prayer', 'Protects the weak', 'a', 'For thou art not a God that hath pleasure in wickedness: neither shall evil dwell with thee (Psalm 5:4).'),
('Psalms', 5, 'teens', 3, 'What does David do in the morning, and then he waits?', 'He directs his prayer to God and looks up', 'He reads the law', 'He prepares offerings', 'He calls the priests', 'a', 'In the morning will I direct my prayer unto thee, and will look up (Psalm 5:3).'),
('Psalms', 5, 'teens', 4, 'Who does God destroy according to Psalm 5:6?', 'The proud and the boastful', 'Those that speak leasing; the LORD will abhor the bloody and deceitful man', 'The enemies of Israel', 'The foolish and ignorant', 'a', 'Thou shalt destroy them that speak leasing: the LORD will abhor the bloody and deceitful man (Psalm 5:6).'),
('Psalms', 5, 'teens', 5, 'What does David describe his enemies'' throats as?', 'An open fountain', 'An open sepulchre', 'A roaring lion', 'A deep pit', 'a', 'For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre (Psalm 5:9). Paul also quotes this in Romans 3:13.'),
-- Adults
('Psalms', 5, 'adults', 1, 'What does Paul quote from Psalm 5:9 in his indictment of universal sin in Romans 3?', '"Their throat is an open sepulchre" to show the wickedness of the human tongue', 'Their feet are swift to shed blood', 'There is no fear of God before their eyes', 'None doeth good, no not one', 'a', 'Paul quotes Psalm 5:9 — "Their throat is an open sepulchre; with their tongues they have used deceit" — in Romans 3:13.'),
('Psalms', 5, 'adults', 2, 'In what posture does David approach the temple according to Psalm 5:7?', 'Standing with arms raised', 'In the multitude of thy mercy; I will worship toward thy holy temple', 'Lying prostrate at the gate', 'Kneeling at the altar', 'a', 'In the multitude of thy mercy...will I worship toward thy holy temple (Psalm 5:7).'),
('Psalms', 5, 'adults', 3, 'What does the word "meditate" in the superscription of Psalm 5 ("give ear to my meditation") indicate?', 'Silent study', 'A murmuring or sighing prayer — inner speech offered to God', 'A written prayer', 'A musical composition', 'a', '"Give ear to my meditation" (Psalm 5:1) — the Hebrew word higgayon implies a murmuring or sighing, deeply personal inner prayer.'),
('Psalms', 5, 'adults', 4, 'What accusation does David make against his enemies in Psalm 5:9 concerning their mouth?', 'They speak too much', 'There is no faithfulness in their mouth; their inward part is very wickedness', 'They blaspheme God''s name', 'They speak against the king', 'a', 'For there is no faithfulness in their mouth; their inward part is very wickedness; their throat is an open sepulchre (Psalm 5:9).'),
('Psalms', 5, 'adults', 5, 'What does God''s favour being like a shield in Psalm 5:12 add to the metaphor of God''s protection?', 'It is temporary', 'God''s favour is an all-surrounding defence encircling the righteous', 'It is only for warriors', 'It only covers the front', 'a', 'With favour wilt thou compass him as with a shield (Psalm 5:12) — "compass" means to surround on all sides.'),
('Psalms', 5, 'adults', 6, 'What does "the foolish shall not stand in thy sight" in Psalm 5:5 teach about God?', 'God pities all fools', 'God''s holiness is absolutely incompatible with sin and foolishness', 'Foolish people are excluded from prayer', 'God ignores the foolish', 'a', 'The foolish shall not stand in thy sight: thou hatest all workers of iniquity (Psalm 5:5) — God''s holy character cannot tolerate iniquity.'),
('Psalms', 5, 'adults', 7, 'David says God will "destroy" those who speak leasing (lies). What Hebrew verb is used and what does it convey?', 'Natash — to abandon', 'Abad — to cause to perish or destroy utterly', 'Shamar — to keep', 'Radaph — to pursue', 'a', 'Thou shalt destroy them that speak leasing (Psalm 5:6) — the verb conveys complete destruction, not merely punishment.'),
('Psalms', 5, 'adults', 8, 'How does the structure of Psalm 5 move from petition to confidence?', 'It begins with praise and ends with lament', 'It opens with morning prayer (vv.1-3), describes God''s character as judge of evil (vv.4-6), seeks guidance (vv.7-8), exposes enemies (vv.9-10), and closes with confident blessing of the righteous (vv.11-12)', 'It is a simple two-part psalm', 'It has no movement — it is purely a lament', 'a', 'Psalm 5 moves: morning petition → God''s holy character → guidance request → enemies exposed → final confidence in God''s blessing (Psalm 5:1-12).');

-- ═══ Psalms Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 6, 'kids', 1, 'What does David do on his bed in Psalm 6 because of his sorrow?', 'He makes it swim with tears', 'He reads the scrolls', 'He sings songs', 'He thanks God', 'a', 'I water my couch with my tears (Psalm 6:6).'),
('Psalms', 6, 'kids', 2, 'What does David ask God NOT to do to him?', 'Rebuke him in anger', 'Leave him alone', 'Send him away', 'Forget his name', 'a', 'O LORD, rebuke me not in thine anger, neither chasten me in thy hot displeasure (Psalm 6:1).'),
('Psalms', 6, 'kids', 3, 'What does David say God has heard?', 'His weeping', 'His singing', 'His questions', 'His commands', 'a', 'The LORD hath heard the voice of my weeping (Psalm 6:8).'),
-- Teens
('Psalms', 6, 'teens', 1, 'What physical suffering does David describe in Psalm 6:2?', 'He is vexed and his bones are troubled', 'He is starving and thirsty', 'He has been wounded in battle', 'He has lost his sight', 'a', 'Have mercy upon me, O LORD; for I am weak: O LORD, heal me; for my bones are vexed (Psalm 6:2).'),
('Psalms', 6, 'teens', 2, 'How long does David cry out in Psalm 6:3?', '"O LORD, how long?"', '"Until I die"', '"For forty days"', '"Seven nights"', 'a', 'My soul is also sore vexed: but thou, O LORD, how long? (Psalm 6:3).'),
('Psalms', 6, 'teens', 3, 'What argument does David make regarding death and praising God in Psalm 6:5?', 'The dead praise God in heaven', 'In death there is no remembrance of God; in the grave none gives thanks', 'The dying cry out louder than the living', 'Death brings rest from praising', 'a', 'For in death there is no remembrance of thee: in the grave who shall give thee thanks? (Psalm 6:5).'),
('Psalms', 6, 'teens', 4, 'What does David say has happened to his eye in Psalm 6:7?', 'It is consumed with grief', 'It has been healed', 'It has grown dim with age', 'It has been blinded by enemies', 'a', 'Mine eye is consumed because of grief; it waxeth old because of all mine enemies (Psalm 6:7).'),
('Psalms', 6, 'teens', 5, 'What is David''s confident declaration to workers of iniquity at the end of Psalm 6?', 'I will pursue you', 'Depart from me, for the LORD hath heard my supplication', 'You will be destroyed', 'I forgive you', 'a', 'Depart from me, all ye workers of iniquity; for the LORD hath heard the voice of my weeping (Psalm 6:8).'),
-- Adults
('Psalms', 6, 'adults', 1, 'Psalm 6 is the first of how many traditional "Penitential Psalms" in the Psalter?', 'Five', 'Seven', 'Ten', 'Three', 'a', 'Psalm 6 is the first of the seven traditional Penitential Psalms: 6, 32, 38, 51, 102, 130, and 143.'),
('Psalms', 6, 'adults', 2, 'What does David mean by asking God to "return" in Psalm 6:4?', 'To return to the temple', 'To turn back to David in mercy after withdrawing His favour', 'To return the ark of the covenant', 'To return from battle', 'a', 'Return, O LORD, deliver my soul: oh save me for thy mercies'' sake (Psalm 6:4) — David feels God has turned away and pleads for restored favour.'),
('Psalms', 6, 'adults', 3, 'What does the phrase "mine eye is consumed with grief" in Psalm 6:7 communicate about David''s condition?', 'He has a physical eye disease', 'His grief has been so intense and prolonged that it has physically deteriorated his sight', 'He is exaggerating for poetic effect', 'He has been crying in darkness', 'a', 'Mine eye is consumed because of grief (Psalm 6:7) — intense grief was understood to physically affect the eyes in ancient Hebrew thought.'),
('Psalms', 6, 'adults', 4, 'What is the theological argument David makes in Psalm 6:5 to motivate God to save him?', 'That he is righteous and deserves saving', 'That God receives no praise from the dead, so his death would diminish God''s worship', 'That his enemies will mock God if he dies', 'That his family will suffer', 'a', 'In death there is no remembrance of thee: in the grave who shall give thee thanks? (Psalm 6:5) — David appeals to God''s interest in being praised.'),
('Psalms', 6, 'adults', 5, 'What transition occurs between verse 7 and verses 8-10 of Psalm 6?', 'The psalm becomes a praise song', 'A sudden shift from lament to certainty — David moves from weeping to bold confidence that God has heard', 'The psalm changes authors', 'David begins to describe his enemies in detail', 'a', 'The psalm shifts from anguish (vv.1-7) to assurance (vv.8-10): "The LORD hath heard the voice of my weeping" (Psalm 6:8).'),
('Psalms', 6, 'adults', 6, 'What three affirmations does David make in Psalm 6:9?', 'God is holy, mighty, and near', 'The LORD hath heard my supplication; the LORD will receive my prayer', 'God forgives, heals, and restores', 'God is my rock, shield, and strength', 'a', 'The LORD hath heard my supplication; the LORD will receive my prayer (Psalm 6:9).'),
('Psalms', 6, 'adults', 7, 'What will happen to David''s enemies according to Psalm 6:10?', 'They will be imprisoned', 'They shall be ashamed and sore vexed; they shall return and be ashamed suddenly', 'They will be destroyed by fire', 'They will flee into the wilderness', 'a', 'Let all mine enemies be ashamed and sore vexed: let them return and be ashamed suddenly (Psalm 6:10).'),
('Psalms', 6, 'adults', 8, 'What does the superscription "to the chief Musician on Neginoth upon Sheminith" indicate?', 'David wrote it alone without music', 'It is a liturgical direction specifying a stringed instrument (Neginoth) and possibly an eight-stringed instrument or bass register (Sheminith)', 'It was a private prayer not for public use', 'It was written after a military victory', 'a', 'Neginoth refers to stringed instruments; Sheminith likely means "the eighth" — possibly a musical key or an eight-stringed instrument (Psalm 6 superscription).');

-- ═══ Psalms Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 7, 'kids', 1, 'In whom does David put his trust in Psalm 7?', 'In the LORD my God', 'In his mighty warriors', 'In the walls of the city', 'In the priests', 'a', 'O LORD my God, in thee do I put my trust (Psalm 7:1).'),
('Psalms', 7, 'kids', 2, 'What does David say God does to the hearts and minds?', 'Tries them', 'Fills them with joy', 'Reads them', 'Opens them', 'a', 'The righteous God trieth the hearts and reins (Psalm 7:9).'),
('Psalms', 7, 'kids', 3, 'What does David say will happen to the wicked man''s trouble?', 'It will return upon his own head', 'It will go away', 'It will stay forever', 'It will spread to others', 'a', 'His mischief shall return upon his own head, and his violent dealing shall come down upon his own pate (Psalm 7:16).'),
-- Teens
('Psalms', 7, 'teens', 1, 'What does David ask God to do if he has done wrong to his friend in Psalm 7:3-5?', 'Forgive him quickly', 'Let the enemy trample him to the ground', 'Take away his kingship', 'Send him into exile', 'a', 'If I have rewarded evil unto him that was at peace with me...Let the enemy persecute my soul, and take it (Psalm 7:4-5).'),
('Psalms', 7, 'teens', 2, 'What does God do daily according to Psalm 7:11?', 'God is angry with the wicked every day', 'God blesses the righteous every day', 'God tests the wicked every day', 'God forgives the wicked every day', 'a', 'God judgeth the righteous, and God is angry with the wicked every day (Psalm 7:11).'),
('Psalms', 7, 'teens', 3, 'What three weapons does God prepare against the wicked in Psalm 7:12-13?', 'A sword, a bow, and fire', 'His sword, his bow, and his ordained instruments', 'Arrows, a spear, and a lance', 'Thunder, lightning, and hailstones', 'a', 'He hath bent his bow, and made it ready. He hath also prepared for him the instruments of death; he ordaineth his arrows against the persecutors (Psalm 7:12-13).'),
('Psalms', 7, 'teens', 4, 'What three things does the wicked man labour to bring forth in Psalm 7:14?', 'War, famine, and disease', 'Vanity, mischief, and falsehood', 'Pride, greed, and violence', 'Deceit, hatred, and murder', 'a', 'He travaileth with iniquity, and hath conceived mischief, and brought forth falsehood (Psalm 7:14).'),
('Psalms', 7, 'teens', 5, 'How does David end Psalm 7?', 'With a lament', 'I will praise the LORD according to his righteousness', 'With a curse on his enemies', 'With a prayer for the king', 'a', 'I will praise the LORD according to his righteousness: and will sing praise to the name of the LORD most high (Psalm 7:17).'),
-- Adults
('Psalms', 7, 'adults', 1, 'What is a "Shiggaion" as indicated in the superscription of Psalm 7?', 'A private prayer', 'A wild, passionate lyric or wandering song — possibly indicating an irregular or emotional meter', 'A temple song sung by Levites', 'A victory chant', 'a', 'Shiggaion (Psalm 7:1 superscription) is thought to denote a wild, passionate, or irregular lyric — a form expressing intense emotion.'),
('Psalms', 7, 'adults', 2, 'Who is Cush the Benjamite mentioned in the title, and why is he significant?', 'A foreign king', 'An otherwise unknown personal enemy of David — the occasion for this passionate prayer for justice', 'A general in David''s army', 'A false prophet', 'a', 'Cush the Benjamite (Psalm 7 title) is unknown outside this psalm, suggesting a specific personal crisis that gave rise to David''s prayer for vindication.'),
('Psalms', 7, 'adults', 3, 'What does David mean by "reins" in "God trieth the hearts and reins" in Psalm 7:9?', 'The external deeds', 'The kidneys — the seat of the deepest emotions and secret thoughts in Hebrew thought', 'The mind and intellect', 'The words of the mouth', 'a', 'The "reins" (kidneys) represented the seat of deepest emotions and secret motives in Hebrew thought (Psalm 7:9).'),
('Psalms', 7, 'adults', 4, 'What metaphor does David use in Psalm 7:15 for the wicked man''s self-destruction?', 'He builds a tower that falls on him', 'He made a pit, and digged it, and is fallen into the ditch which he made', 'He planted thorns and was pricked by them', 'He sharpened a sword and was cut by it', 'a', 'He made a pit, and digged it, and is fallen into the ditch which he made (Psalm 7:15).'),
('Psalms', 7, 'adults', 5, 'What does the phrase "God is angry with the wicked every day" in Psalm 7:11 teach against?', 'It teaches that God is cruel', 'It teaches against a false view of a morally indifferent God who is unconcerned with wickedness', 'It teaches that all people are under constant judgment', 'It teaches that God''s anger is permanent', 'a', 'God judgeth the righteous, and God is angry with the wicked every day (Psalm 7:11) — refuting the notion of divine indifference to evil.'),
('Psalms', 7, 'adults', 6, 'What does David''s self-imprecatory oath in Psalm 7:3-5 reveal about his character?', 'He is arrogant and certain of his own innocence', 'He is willing to accept punishment if he is guilty, showing integrity and submission to God''s justice', 'He is testing God', 'He has no enemies', 'a', 'David''s oath — "if I have done iniquity, let mine enemy pursue me" (Psalm 7:3-5) — reveals integrity and genuine trust in God as judge.'),
('Psalms', 7, 'adults', 7, 'What three attributes of God as judge does Psalm 7 emphasize?', 'Mercy, patience, and love', 'Righteousness (v.9), daily anger against wickedness (v.11), and absolute justice (v.16)', 'Power, knowledge, and sovereignty', 'Holiness, wisdom, and faithfulness', 'a', 'Psalm 7 emphasizes: God tries hearts (v.9), is angry with the wicked every day (v.11), and ensures mischief returns on the wicked (v.16).'),
('Psalms', 7, 'adults', 8, 'What does the phrase "my defence is of God" in Psalm 7:10 reveal about David''s legal strategy?', 'He trusts human courts', 'He bypasses earthly courts entirely, appealing to God as the supreme judge and vindicator', 'He relies on his own righteousness', 'He asks the priests to judge his case', 'a', 'My defence is of God, which saveth the upright in heart (Psalm 7:10) — David''s appeal is to the divine court, not human tribunals.');

-- ═══ Psalms Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 8, 'kids', 1, 'What question does David ask about mankind in Psalm 8?', 'What is man, that thou art mindful of him?', 'Where does man come from?', 'Why does man sin?', 'How long shall man live?', 'a', 'What is man, that thou art mindful of him? and the son of man, that thou visitest him? (Psalm 8:4).'),
('Psalms', 8, 'kids', 2, 'What did God put man in charge of?', 'The works of his hands', 'The temple of God', 'The armies of Israel', 'The stars and sky', 'a', 'Thou madest him to have dominion over the works of thy hands; thou hast put all things under his feet (Psalm 8:6).'),
('Psalms', 8, 'kids', 3, 'How does Psalm 8 begin and end?', 'With a lament', 'O LORD our Lord, how excellent is thy name in all the earth!', 'With praise for the law', 'With a prayer for the king', 'a', 'O LORD our Lord, how excellent is thy name in all the earth! (Psalm 8:1, 9) — the psalm opens and closes with the same refrain.'),
-- Teens
('Psalms', 8, 'teens', 1, 'Who does God ordain strength out of to silence the enemy, according to Psalm 8:2?', 'The mouths of babes and sucklings', 'The mouths of prophets', 'The mouths of the priests', 'The mouths of warriors', 'a', 'Out of the mouth of babes and sucklings hast thou ordained strength because of thine enemies (Psalm 8:2).'),
('Psalms', 8, 'teens', 2, 'What does David see when he considers at night that makes him marvel at human significance?', 'The moon and the stars God hath ordained', 'The armies of the nations', 'The great rivers and seas', 'The mountains and valleys', 'a', 'When I consider thy heavens, the work of thy fingers, the moon and the stars, which thou hast ordained (Psalm 8:3).'),
('Psalms', 8, 'teens', 3, 'What does God crown man with in Psalm 8:5?', 'Glory and honour', 'Wisdom and understanding', 'Strength and beauty', 'Gold and silver', 'a', 'Thou hast crowned him with glory and honour (Psalm 8:5).'),
('Psalms', 8, 'teens', 4, 'What animals are listed as being under man''s dominion in Psalm 8?', 'Lions, eagles, and serpents', 'Sheep, oxen, beasts of the field, fowl, fish, and things of the sea', 'Horses, camels, and donkeys', 'Bears, wolves, and deer', 'a', 'All sheep and oxen, yea, and the beasts of the field; The fowl of the air, and the fish of the sea (Psalm 8:7-8).'),
('Psalms', 8, 'teens', 5, 'Jesus quoted Psalm 8:2 in what New Testament situation?', 'When he was baptized', 'When children praised him in the temple and the priests objected', 'When he fed the five thousand', 'When he entered Jerusalem', 'a', 'Jesus quoted Psalm 8:2 — "Out of the mouth of babes and sucklings thou hast perfected praise" — when children cried Hosanna in the temple (Matthew 21:16).'),
-- Adults
('Psalms', 8, 'adults', 1, 'How does the New Testament book of Hebrews apply Psalm 8:4-6 to Jesus?', 'To show Jesus was a human prophet', 'Hebrews 2:6-9 applies it to Christ, who was made a little lower than the angels through incarnation and death, then crowned with glory', 'To show man''s fallen state', 'To prove Jesus was always exalted', 'a', 'Hebrews 2:6-9 quotes Psalm 8:4-6, applying the "son of man" who is crowned with glory and honour to Jesus after his suffering and resurrection.'),
('Psalms', 8, 'adults', 2, 'What is the significance of Psalm 8:2 being quoted in Matthew 21:16 when children praised Jesus?', 'Jesus corrected the children', 'Jesus identified himself as the LORD whose praise is ordained from children, implying divine identity', 'The children were mistaken', 'Jesus was embarrassed by the children', 'a', 'Jesus quoted Psalm 8:2 — "Out of the mouth of babes and sucklings thou hast perfected praise" — claiming the children''s Hosanna was divinely ordained (Matthew 21:16).'),
('Psalms', 8, 'adults', 3, 'What does it mean that man is made "a little lower than the angels" in Psalm 8:5?', 'Man is inferior to God and angels in all ways', 'Man is only slightly below angelic beings in the created order, yet given extraordinary dignity and dominion', 'Man will never reach angelic status', 'Man was originally an angel', 'a', 'Thou hast made him a little lower than the angels, and hast crowned him with glory and honour (Psalm 8:5) — man holds a uniquely high position in creation.'),
('Psalms', 8, 'adults', 4, 'What Hebrew word is translated "angels" in Psalm 8:5 and what does it actually mean?', 'Mal''ak — messenger', 'Elohim — divine beings or God himself', 'Seraphim — burning ones', 'Cherubim — covering ones', 'a', 'The Hebrew word is Elohim (divine beings), which the Septuagint renders as "angels." This makes the verse even more striking in Hebrews 2:7.'),
('Psalms', 8, 'adults', 5, 'Paul quotes "thou hast put all things under his feet" from Psalm 8:6 in what epistle?', 'Galatians', '1 Corinthians 15:27, applying it to Christ''s ultimate dominion over all things', 'Romans 8', 'Ephesians 1', 'a', 'Paul quotes Psalm 8:6 in 1 Corinthians 15:27 and Ephesians 1:22, applying Christ''s universal dominion to the resurrection and the consummation of all things.'),
('Psalms', 8, 'adults', 6, 'What is the rhetorical and theological effect of Psalm 8 beginning and ending with the same refrain?', 'It is a structural accident', 'It creates an inclusio — the entire psalm is framed by and grounded in the excellence of God''s name, subordinating human dignity to divine glory', 'It makes the psalm easier to memorize', 'It shows the psalm was incomplete', 'a', 'The inclusio of "O LORD our Lord, how excellent is thy name in all the earth!" (Psalm 8:1, 9) grounds all human dignity in God''s glory, not in humanity itself.'),
('Psalms', 8, 'adults', 7, 'How does Psalm 8 connect to the creation mandate of Genesis 1:26-28?', 'It replaces the Genesis mandate', 'It echoes the creation mandate by celebrating man''s God-given dominion over creation — framing the psalm as a meditation on Genesis 1', 'It contradicts Genesis 1 by diminishing man', 'It describes creation after the fall', 'a', 'Psalm 8:6-8 directly echoes Genesis 1:26-28 — man''s dominion over fish, fowl, and beast — framing the psalm as a lyric meditation on the creation mandate.'),
('Psalms', 8, 'adults', 8, 'What does the designation "To the chief Musician upon Gittith" in the superscription suggest?', 'The psalm was written for private use', 'It may indicate a tune named after Gath or a musical instrument associated with Gath', 'It was composed in exile', 'It was written for the Feast of Passover', 'a', 'Gittith in Psalm 8''s superscription may denote a melody from Gath, an instrument from Gath, or a tune associated with the winepress (gath means winepress in Hebrew).');

-- ═══ Psalms Chapter 9 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 9, 'kids', 1, 'What does David say he will do with his whole heart in Psalm 9?', 'Praise the LORD', 'Fast and pray', 'Read the law', 'Build an altar', 'a', 'I will praise thee, O LORD, with my whole heart; I will shew forth all thy marvellous works (Psalm 9:1).'),
('Psalms', 9, 'kids', 2, 'Where does David say the LORD sits?', 'Upon his throne for ever', 'In the temple in Jerusalem', 'In the clouds of heaven', 'On top of a mountain', 'a', 'The LORD shall endure for ever: he hath prepared his throne for judgment (Psalm 9:7).'),
('Psalms', 9, 'kids', 3, 'What does David say the LORD has not forgotten?', 'The cry of the humble', 'The songs of Israel', 'The names of the prophets', 'The prayers of the priests', 'a', 'For he that avengeth blood remembereth them: he forgetteth not the cry of the humble (Psalm 9:12).'),
-- Teens
('Psalms', 9, 'teens', 1, 'What happens to the nations that forget God according to Psalm 9:17?', 'They are turned into hell', 'They lose their wealth', 'They are scattered', 'They are conquered by enemies', 'a', 'The wicked shall be turned into hell, and all the nations that forget God (Psalm 9:17).'),
('Psalms', 9, 'teens', 2, 'How is the LORD known according to Psalm 9:16?', 'By the judgment he executeth', 'By his miracles among the nations', 'By his commandments to Israel', 'By the temple he inhabits', 'a', 'The LORD is known by the judgment which he executeth (Psalm 9:16).'),
('Psalms', 9, 'teens', 3, 'What does David say about the needy in Psalm 9:18?', 'The needy shall not always be forgotten', 'The needy will be rewarded in heaven', 'The needy should trust in themselves', 'The needy are blessed above all', 'a', 'For the needy shall not alway be forgotten: the expectation of the poor shall not perish for ever (Psalm 9:18).'),
('Psalms', 9, 'teens', 4, 'What does David ask God to do to the nations in Psalm 9:19?', 'Judge the nations; let them know they are but men', 'Destroy the nations with fire', 'Scatter the nations to the winds', 'Lead the nations to repentance', 'a', 'Arise, O LORD; let not man prevail: let the heathen be judged in thy sight (Psalm 9:19).'),
('Psalms', 9, 'teens', 5, 'What term for death is used in Psalm 9:13 when David prays about being lifted up?', 'The gates of death', 'The shadow of death', 'The valley of death', 'The pit of destruction', 'a', 'Thou that liftest me up from the gates of death (Psalm 9:13).'),
-- Adults
('Psalms', 9, 'adults', 1, 'Psalms 9 and 10 together form what literary structure that is partially visible in their Hebrew text?', 'A chiasm', 'An acrostic poem following the Hebrew alphabet', 'A dialogue between two voices', 'A royal decree', 'a', 'Psalms 9-10 together form an incomplete alphabetic acrostic in Hebrew, suggesting they were originally one poem later divided.'),
('Psalms', 9, 'adults', 2, 'What does "Muth-labben" in the superscription of Psalm 9 most likely refer to?', 'A type of offering', 'A musical tune or instrument — possibly meaning "death of the son" or a tune by that name', 'A feast day', 'A particular enemy of David', 'a', '"To the chief Musician upon Muth-labben" (Psalm 9 superscription) — Muth-labben is thought to be a musical tune title, possibly meaning "death of the son."'),
('Psalms', 9, 'adults', 3, 'What does the word "Higgaion" in Psalm 9:16 mean?', 'Praise God', 'A musical term for meditation or a solemn sound — often associated with a stringed interlude', 'Forever', 'Amen', 'a', '"Higgaion. Selah" (Psalm 9:16) — Higgaion is a musical term likely indicating a solemn, meditative interlude on stringed instruments.'),
('Psalms', 9, 'adults', 4, 'What is the theological significance of God being enthroned forever as judge in Psalm 9:7-8?', 'It is a mythological claim with no practical meaning', 'It guarantees that history is not morally random — God will ultimately administer perfect justice to all nations and individuals', 'It only applies to Israel', 'It suggests God judges nations but not individuals', 'a', 'The LORD shall endure for ever...he shall judge the world in righteousness (Psalm 9:7-8) — God''s eternal throne guarantees ultimate moral accountability.'),
('Psalms', 9, 'adults', 5, 'What is the "snare" that the wicked are caught in according to Psalm 9:15-16?', 'A trap set by David''s army', 'The work of their own hands — the nations sunk in the pit they made and caught in their own net', 'A divine punishment sent from heaven', 'A natural disaster', 'a', 'In the work of his own hands is the wicked snared. Higgaion. Selah (Psalm 9:16) — poetic justice as the wicked are undone by their own schemes.'),
('Psalms', 9, 'adults', 6, 'What does David''s praise "with my whole heart" in Psalm 9:1 teach about the nature of true worship?', 'Worship should be loud and public', 'True worship involves the total commitment of the inner person, not merely external ritual', 'Worship is only valid in the temple', 'Worship requires others to be present', 'a', 'I will praise thee, O LORD, with my whole heart (Psalm 9:1) — wholehearted praise contrasts with formalism and half-hearted devotion.'),
('Psalms', 9, 'adults', 7, 'What does David''s mention of the "gates of Zion" in Psalm 9:14 represent?', 'A military fortification', 'The place of public life and worship — where God''s salvation is declared to the congregation', 'The entrance to the temple courts', 'The boundary of the kingdom', 'a', 'That I may shew forth all thy praise in the gates of the daughter of Zion (Psalm 9:14) — gates were the public forum of ancient city life.'),
('Psalms', 9, 'adults', 8, 'How does Psalm 9:18 address the apparent prosperity of the wicked and suffering of the righteous?', 'By denying that the poor suffer', 'By asserting that the expectation of the poor shall not perish for ever — God''s justice operates beyond immediate circumstances', 'By promising immediate reversal', 'By teaching that suffering is punishment for sin', 'a', 'The needy shall not alway be forgotten: the expectation of the poor shall not perish for ever (Psalm 9:18) — hope deferred is not hope denied.');

-- ═══ Psalms Chapter 10 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 10, 'kids', 1, 'What does David ask God at the beginning of Psalm 10?', 'Why standest thou afar off, O LORD?', 'Where hast thou gone, O LORD?', 'Why art thou silent, O LORD?', 'When wilt thou come, O LORD?', 'a', 'Why standest thou afar off, O LORD? why hidest thou thyself in times of trouble? (Psalm 10:1).'),
('Psalms', 10, 'kids', 2, 'What does the wicked man say in his heart?', 'There is no God', 'I am strong', 'No one can see me', 'I will win all battles', 'a', 'The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts (Psalm 10:4). Also: "He hath said in his heart, I shall not be moved" (Psalm 10:6).'),
('Psalms', 10, 'kids', 3, 'What does David say God has heard regarding the humble?', 'The desire of the humble', 'The singing of the humble', 'The tears of the humble', 'The names of the humble', 'a', 'LORD, thou hast heard the desire of the humble (Psalm 10:17).'),
-- Teens
('Psalms', 10, 'teens', 1, 'What does the wicked man think in his heart about God''s judgment according to Psalm 10:6?', 'He shall not be moved, for he shall never be in adversity', 'God will punish him eventually', 'His wickedness is hidden from God', 'God will forgive everything', 'a', 'He hath said in his heart, I shall not be moved: for I shall never be in adversity (Psalm 10:6).'),
('Psalms', 10, 'teens', 2, 'How does the wicked man describe his attitude toward God in Psalm 10:4?', 'He secretly fears God', 'God is not in all his thoughts', 'He prays but disobeys', 'He mocks the prophets', 'a', 'The wicked, through the pride of his countenance, will not seek after God: God is not in all his thoughts (Psalm 10:4).'),
('Psalms', 10, 'teens', 3, 'What does the wicked man''s mouth contain according to Psalm 10:7?', 'Cursing, deceit, and fraud', 'Loud boasting and threats', 'False prophecies', 'Idle words and flattery', 'a', 'His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity (Psalm 10:7).'),
('Psalms', 10, 'teens', 4, 'Who does the wicked man lurk to prey upon in Psalm 10:9?', 'The poor', 'The rulers', 'The priests', 'The foreigners', 'a', 'He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor (Psalm 10:9).'),
('Psalms', 10, 'teens', 5, 'What does David ask God to do in Psalm 10:12?', 'Arise, O LORD; O God, lift up thine hand: forget not the humble', 'Come down and destroy the wicked', 'Open the eyes of the people', 'Send a flood on the wicked', 'a', 'Arise, O LORD; O God, lift up thine hand: forget not the humble (Psalm 10:12).'),
-- Adults
('Psalms', 10, 'adults', 1, 'What is the theological problem raised in Psalm 10:1 that theologians call "the hiddenness of God"?', 'God does not exist', 'Why does God appear absent and distant when the wicked prosper and the humble suffer?', 'God is too distant to care about humanity', 'God only appears in the temple', 'a', 'Why standest thou afar off, O LORD? why hidest thou thyself in times of trouble? (Psalm 10:1) — the classic lament over apparent divine absence.'),
('Psalms', 10, 'adults', 2, 'What four sins of the wicked man''s mouth are listed in Psalm 10:7?', 'Pride, greed, lust, envy', 'Cursing, deceit, fraud, mischief and vanity under the tongue', 'Lies, threats, blasphemy, and flattery', 'Gossip, boasting, slander, and false witness', 'a', 'His mouth is full of cursing and deceit and fraud: under his tongue is mischief and vanity (Psalm 10:7).'),
('Psalms', 10, 'adults', 3, 'What does the wicked man say in Psalm 10:11 about God that reveals his theological error?', 'God does not exist', 'God hath forgotten: he hideth his face; he will never see it', 'God is only for Israel', 'God has given him prosperity as approval', 'a', 'He hath said in his heart, God hath forgotten: he hideth his face; he will never see it (Psalm 10:11).'),
('Psalms', 10, 'adults', 4, 'What does "prepare their heart" in Psalm 10:17 indicate about how God answers prayer?', 'God bypasses human will', 'God works inwardly, preparing the hearts of the humble to receive his answer before responding', 'God only answers spontaneous prayers', 'God prepares the heart of the wicked', 'a', 'LORD, thou hast heard the desire of the humble: thou wilt prepare their heart, thou wilt cause thine ear to hear (Psalm 10:17).'),
('Psalms', 10, 'adults', 5, 'How does the lion imagery in Psalm 10:9 characterize the nature of the wicked''s predatory behaviour?', 'It shows they are cowardly', 'They patiently and cunningly ambush the vulnerable, attacking when defences are down', 'They hunt openly and boldly', 'They attack only the powerful', 'a', 'He lieth in wait secretly as a lion in his den: he lieth in wait to catch the poor (Psalm 10:9).'),
('Psalms', 10, 'adults', 6, 'What does the phrase "The LORD is King for ever and ever" in Psalm 10:16 do to the preceding lament?', 'It contradicts the lament', 'It resolves the psalm''s crisis by asserting God''s eternal sovereignty over all apparent disorder', 'It begins a new psalm', 'It is a liturgical addition', 'a', 'The LORD is King for ever and ever: the heathen are perished out of his land (Psalm 10:16) — the affirmation of God''s eternal kingship resolves the lament.'),
('Psalms', 10, 'adults', 7, 'What does the wicked man''s claim "I shall not be moved" in Psalm 10:6 ironically echo and contradict?', 'The claim of the true believer about God''s protection', 'The confession of faith in Psalm 16:8 and 62:2 — that the righteous, not the wicked, shall not be moved', 'The promises of the Mosaic covenant', 'The words of Abraham''s faith', 'a', 'The wicked''s "I shall not be moved" (Psalm 10:6) ironically mirrors the believer''s confidence in Psalm 16:8 — "I shall not be moved" — but grounded in self rather than God.'),
('Psalms', 10, 'adults', 8, 'What does Psalm 10:18 declare as the ultimate purpose of God''s judgment on behalf of the humble?', 'To punish the nations', 'To judge the fatherless and the oppressed, that the man of the earth may no more oppress', 'To restore Israel''s land', 'To establish Jerusalem as capital of the world', 'a', 'To judge the fatherless and the oppressed, that the man of the earth may no more oppress (Psalm 10:18).');

-- ═══════════════════════════════════════════
-- CHAPTERS 11 – 20
-- ═══════════════════════════════════════════

-- ═══ Psalms Chapter 11 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 11, 'kids', 1, 'Where does David put his trust in Psalm 11?', 'In the LORD', 'In his mighty army', 'In the walls of Jerusalem', 'In his own strength', 'a', 'In the LORD put I my trust (Psalm 11:1).'),
('Psalms', 11, 'kids', 2, 'What does David say the LORD tries in Psalm 11?', 'The righteous', 'The wicked', 'The nations', 'The kings', 'a', 'The LORD trieth the righteous (Psalm 11:5).'),
('Psalms', 11, 'kids', 3, 'What does the LORD love according to Psalm 11:7?', 'Righteousness', 'Offerings', 'Songs of praise', 'Temple worship', 'a', 'For the righteous LORD loveth righteousness; his countenance doth behold the upright (Psalm 11:7).'),
-- Teens
('Psalms', 11, 'teens', 1, 'What do David''s advisors tell him to do like a bird in Psalm 11?', 'Flee to your mountain', 'Sing a new song', 'Build a nest', 'Spread your wings', 'a', 'In the LORD put I my trust: how say ye to my soul, Flee as a bird to your mountain? (Psalm 11:1).'),
('Psalms', 11, 'teens', 2, 'What rhetorical question does David ask when foundations are destroyed?', 'What can the righteous do?', 'Where shall we flee?', 'Who will help us?', 'When will God arise?', 'a', 'If the foundations be destroyed, what can the righteous do? (Psalm 11:3).'),
('Psalms', 11, 'teens', 3, 'Where is the LORD''s throne according to Psalm 11:4?', 'In heaven', 'In Jerusalem', 'In the holy of holies', 'On Mount Sinai', 'a', 'The LORD is in his holy temple, the LORD''s throne is in heaven (Psalm 11:4).'),
('Psalms', 11, 'teens', 4, 'What does the LORD rain on the wicked in Psalm 11:6?', 'Snares, fire, brimstone, and a horrible tempest', 'Floods and darkness', 'Famine and disease', 'Confusion and fear', 'a', 'Upon the wicked he shall rain snares, fire and brimstone, and an horrible tempest: this shall be the portion of their cup (Psalm 11:6).'),
('Psalms', 11, 'teens', 5, 'What do the LORD''s eyes behold as He watches from heaven in Psalm 11?', 'His eyelids try the children of men', 'The armies of Israel', 'The sacrifices in the temple', 'The prayers of the faithful', 'a', 'His eyes behold, his eyelids try, the children of men (Psalm 11:4).'),
-- Adults
('Psalms', 11, 'adults', 1, 'What is the crisis that David''s counselors urge flight from, and why does David refuse?', 'A natural disaster; he trusts in walls', 'A situation where the foundations of order are threatened and the wicked attack; David refuses because the LORD is in his holy temple and sovereign', 'A military siege; he has an army', 'A personal conflict; he has allies', 'a', 'When foundations are destroyed and the wicked bend the bow (Ps 11:2-3), David''s answer is the LORD''s sovereign rule from heaven (Ps 11:4).'),
('Psalms', 11, 'adults', 2, 'What is the significance of the LORD''s "eyelids trying the children of men" in Psalm 11:4?', 'God is asleep', 'It is a Hebrew idiom for careful, scrutinizing observation — God misses nothing', 'God is partially watching', 'God judges only nations', 'a', 'His eyes behold, his eyelids try, the children of men (Psalm 11:4) — the eyelids idiom conveys intent, penetrating observation.'),
('Psalms', 11, 'adults', 3, 'What does the "portion of their cup" in Psalm 11:6 represent for the wicked?', 'A festive drink', 'Their appointed lot or destiny — in this case fire and brimstone', 'A ritual offering', 'Their earthly inheritance', 'a', 'This shall be the portion of their cup (Psalm 11:6) — the cup is a metaphor for one''s divinely appointed destiny or lot.'),
('Psalms', 11, 'adults', 4, 'How does the destruction of Sodom and Gomorrah relate to the imagery in Psalm 11:6?', 'It has no connection', 'The fire and brimstone judgment of Psalm 11:6 directly echoes the destruction of Sodom and Gomorrah in Genesis 19', 'It is a prophecy about a future city', 'It refers to the destruction of Jericho', 'a', 'Fire and brimstone in Psalm 11:6 deliberately echoes the destruction of Sodom and Gomorrah (Genesis 19:24) as the archetypal divine judgment on wickedness.'),
('Psalms', 11, 'adults', 5, 'What does the rhetorical question "If the foundations be destroyed, what can the righteous do?" teach about the relationship between social order and righteousness?', 'That righteousness is impossible without perfect social order', 'That even when earthly foundations collapse, the righteous are anchored to God''s heavenly throne which cannot be destroyed', 'That the righteous must rebuild society', 'That righteousness has no answer to chaos', 'a', 'David''s answer to the destroyed foundations question is the LORD''s eternal throne in heaven (Psalm 11:3-4) — the ultimate foundation cannot be destroyed.'),
('Psalms', 11, 'adults', 6, 'What does it mean that the LORD "loveth righteousness" in Psalm 11:7?', 'God rewards only the morally perfect', 'God''s very nature delights in and is committed to righteousness, making him the ultimate guarantee of justice', 'God prefers good deeds over faith', 'God punishes the wicked immediately', 'a', 'The righteous LORD loveth righteousness; his countenance doth behold the upright (Psalm 11:7).'),
('Psalms', 11, 'adults', 7, 'What is the contrast between Psalm 11:4 (the LORD in his holy temple) and the apparent absence of God in Psalm 10:1?', 'There is no contrast — both psalms say the same thing', 'Psalm 10 laments apparent divine absence; Psalm 11 asserts confident faith in God''s sovereign omniscience from his heavenly throne', 'Psalm 11 corrects Psalm 10''s theology', 'Psalm 10 and 11 describe different gods', 'a', 'Psalm 10 wrestles with God''s apparent hiddenness (Ps 10:1) while Psalm 11 affirms from faith that the LORD''s throne is in heaven and his eyes behold all (Ps 11:4).'),
('Psalms', 11, 'adults', 8, 'What does the promise "his countenance doth behold the upright" in Psalm 11:7 mean for the righteous?', 'They will always prosper materially', 'The upright have the supreme blessing — the face of God turned toward them in favour and fellowship', 'They will live longer than the wicked', 'They will be spared all suffering', 'a', 'His countenance doth behold the upright (Psalm 11:7) — God''s face turned toward someone was the highest blessing in Hebrew thought (cf. Numbers 6:25-26).');

-- ═══ Psalms Chapter 12 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 12, 'kids', 1, 'What does David cry out at the beginning of Psalm 12?', 'Help, LORD', 'Save me, O God', 'Hear my prayer', 'Come quickly, LORD', 'a', 'Help, LORD; for the godly man ceaseth; for the faithful fail from among the children of men (Psalm 12:1).'),
('Psalms', 12, 'kids', 2, 'What does David say the words of the LORD are compared to in Psalm 12?', 'Silver tried in a furnace', 'Gold from the mine', 'Pure water from a spring', 'Honey from the comb', 'a', 'The words of the LORD are pure words: as silver tried in a furnace of earth, purified seven times (Psalm 12:6).'),
('Psalms', 12, 'kids', 3, 'How many times is the silver purified in the furnace in Psalm 12?', 'Seven times', 'Three times', 'Ten times', 'Forty times', 'a', 'As silver tried in a furnace of earth, purified seven times (Psalm 12:6).'),
-- Teens
('Psalms', 12, 'teens', 1, 'What do the wicked speak to each other according to Psalm 12:2?', 'Vanity, and flattering lips, with a double heart', 'Lies and false prophecies', 'Threats and curses', 'Empty promises and boasts', 'a', 'They speak vanity every one with his neighbour: with flattering lips and with a double heart do they speak (Psalm 12:2).'),
('Psalms', 12, 'teens', 2, 'What do the proud say about their tongues and lips in Psalm 12:4?', 'Our lips are our own: who is lord over us?', 'Our words are truth and cannot be stopped', 'Our tongue is stronger than any sword', 'Our mouth speaks wisdom that none can deny', 'a', 'Who have said, With our tongue will we prevail; our lips are our own: who is lord over us? (Psalm 12:4).'),
('Psalms', 12, 'teens', 3, 'What does God say He will do because of the oppression of the poor in Psalm 12:5?', 'Now will I arise, saith the LORD', 'I will send my angel to fight', 'I will rain fire on the oppressors', 'I will raise up a deliverer', 'a', 'For the oppression of the poor, for the sighing of the needy, now will I arise, saith the LORD (Psalm 12:5).'),
('Psalms', 12, 'teens', 4, 'What two things will God cut off according to Psalm 12:3?', 'Flattering lips and the tongue that speaketh proud things', 'The sword and the spear', 'The wicked and the violent', 'Liars and false prophets', 'a', 'The LORD shall cut off all flattering lips, and the tongue that speaketh proud things (Psalm 12:3).'),
('Psalms', 12, 'teens', 5, 'What promise does God make to those who are set in safety?', 'I will set him in safety from him that puffeth at him', 'I will give them victory over their enemies', 'I will surround them with angels', 'I will bless them with prosperity', 'a', 'I will set him in safety from him that puffeth at him (Psalm 12:5).'),
-- Adults
('Psalms', 12, 'adults', 1, 'What does "a double heart" in Psalm 12:2 literally mean in Hebrew?', 'Two physical hearts', 'A heart-and-a-heart — insincerity, saying one thing outwardly while thinking another inwardly', 'An extra measure of evil', 'A divided mind', 'a', '"With a double heart" (Psalm 12:2) — Hebrew: lev va-lev (heart and heart) — the classic biblical expression for duplicity and insincerity.'),
('Psalms', 12, 'adults', 2, 'What is the significance of silver being purified "seven times" in Psalm 12:6?', 'Silver must be physically purified exactly seven times', 'Seven is the number of completeness in Hebrew — representing absolute, perfect purity with nothing to hide', 'It took seven processes in ancient metallurgy', 'Seven was David''s favourite number', 'a', 'Purified seven times (Psalm 12:6) — seven in Hebrew thought represents completeness, so the words of the LORD are perfectly, completely pure.'),
('Psalms', 12, 'adults', 3, 'What social crisis drives the lament in Psalm 12:1-2?', 'Military defeat', 'The collapse of truthful, faithful speech — the godly have ceased and the faithful have vanished from society', 'Famine and drought', 'Apostasy in the temple', 'a', 'The godly man ceaseth; the faithful fail from among the children of men. They speak vanity (Psalm 12:1-2) — a crisis of lying and faithlessness in public life.'),
('Psalms', 12, 'adults', 4, 'How does God''s direct speech in Psalm 12:5 function uniquely within the psalm?', 'It is a later addition', 'It is a divine oracle embedded in a human lament — God himself breaks in to promise his arising on behalf of the poor', 'It is a quotation of earlier Scripture', 'It is the psalmist speaking for God', 'a', '"Now will I arise, saith the LORD" (Psalm 12:5) is an embedded oracle — a direct divine speech inserted into David''s lament, confirming God''s active response.'),
('Psalms', 12, 'adults', 5, 'What is the contrast the psalm draws between human words and divine words?', 'Human words are loud, divine words are quiet', 'Human words are vanity and flattery (v.2); divine words are pure silver tried seven times (v.6)', 'Human words are many, divine words are few', 'Human words change, divine words are repeated', 'a', 'Psalm 12 explicitly contrasts lying human speech (vv. 2-4) with the pure words of the LORD, like silver tried seven times (v.6).'),
('Psalms', 12, 'adults', 6, 'What does God''s arising specifically for "the oppression of the poor" and "the sighing of the needy" in Psalm 12:5 teach about God''s character?', 'God only helps the wealthy', 'God has a special, active concern for the vulnerable and oppressed, and their cry moves him to action', 'God waits until all prayer fails', 'God helps only those who help themselves', 'a', 'For the oppression of the poor, for the sighing of the needy, now will I arise, saith the LORD (Psalm 12:5) — the suffering of the vulnerable activates divine intervention.'),
('Psalms', 12, 'adults', 7, 'What does "him that puffeth at him" in Psalm 12:5 describe?', 'Physical wind', 'A contemptuous, arrogant mocker who belittles the poor with disdain', 'A foreign army', 'A false prophet', 'a', '"From him that puffeth at him" (Psalm 12:5) — to puff or blow at someone was an expression of contemptuous dismissal in Hebrew culture.'),
('Psalms', 12, 'adults', 8, 'How does the psalm''s ending in verse 8 create a tension with God''s promise in verse 5?', 'There is no tension', 'The psalm ends noting the wicked still walk on every side, showing that God''s promise is received by faith before its visible fulfilment', 'The ending contradicts the promise', 'The ending suggests the promise failed', 'a', 'The wicked walk on every side (Psalm 12:8) — the psalm ends with the reality still dark, teaching that God''s word is trusted before it is seen.');

-- ═══ Psalms Chapter 13 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 13, 'kids', 1, 'What does David ask God at the beginning of Psalm 13?', 'How long wilt thou forget me?', 'Why hast thou left me alone?', 'Where art thou, O God?', 'When wilt thou hear me?', 'a', 'How long wilt thou forget me, O LORD? for ever? (Psalm 13:1).'),
('Psalms', 13, 'kids', 2, 'Even though David was sad, what did he still do in Psalm 13?', 'I have trusted in thy mercy', 'He stopped praying', 'He ran away', 'He gave up', 'a', 'But I have trusted in thy mercy; my heart shall rejoice in thy salvation (Psalm 13:5).'),
('Psalms', 13, 'kids', 3, 'What does David say he will sing to the LORD?', 'Because he hath dealt bountifully with me', 'A new song of joy', 'Songs in the night', 'Praise to his name', 'a', 'I will sing unto the LORD, because he hath dealt bountifully with me (Psalm 13:6).'),
-- Teens
('Psalms', 13, 'teens', 1, 'How many times does David ask "How long" in Psalm 13?', 'Four times', 'Two times', 'Once', 'Three times', 'a', 'David asks "How long" four times in Psalm 13:1-2 — a pattern of intensifying lament.'),
('Psalms', 13, 'teens', 2, 'What does David fear will happen if God does not answer?', 'He will sleep the sleep of death', 'He will lose his kingdom', 'His enemies will destroy Jerusalem', 'He will be forgotten by all', 'a', 'Lest I sleep the sleep of death (Psalm 13:3).'),
('Psalms', 13, 'teens', 3, 'What does David ask God to do to his eyes?', 'Consider and hear me, lighten mine eyes', 'Open them to see the truth', 'Fill them with tears', 'Turn them to the heavens', 'a', 'Consider and hear me, O LORD my God: lighten mine eyes, lest I sleep the sleep of death (Psalm 13:3).'),
('Psalms', 13, 'teens', 4, 'What will happen to David''s enemy if God does not answer?', 'His enemy will say, I have prevailed against him', 'His enemy will be strengthened', 'His enemy will destroy the city', 'His enemy will flee from him', 'a', 'Lest mine enemy say, I have prevailed against him (Psalm 13:4).'),
('Psalms', 13, 'teens', 5, 'What three things does David declare in the final two verses of Psalm 13?', 'I have trusted, my heart shall rejoice, I will sing', 'I will weep, wait, and watch', 'I will fast, pray, and give', 'I will fight, win, and praise', 'a', 'But I have trusted in thy mercy; my heart shall rejoice in thy salvation. I will sing unto the LORD, because he hath dealt bountifully with me (Psalm 13:5-6).'),
-- Adults
('Psalms', 13, 'adults', 1, 'What is the structural pattern of Psalm 13 that makes it a model for biblical lament?', 'It is entirely praise with no complaint', 'It moves from complaint (vv.1-2) to petition (vv.3-4) to trust and praise (vv.5-6)', 'It is a historical narrative', 'It alternates between lament and praise with no resolution', 'a', 'Psalm 13 is a model lament: complaint (1-2) → petition (3-4) → confession of trust and praise (5-6) — the classic three-part lament structure.'),
('Psalms', 13, 'adults', 2, 'What is the theological tension in Psalm 13 between the fourfold "How long?" and the final "I have trusted"?', 'There is no tension — both express the same emotion', 'Faith and suffering coexist — the psalmist moves from desperate questioning to resolute trust without the external circumstances having changed', 'The trust cancels out the lament', 'The lament was insincere', 'a', 'The unanswered "How long?" of verses 1-2 gives way to "I have trusted" (v.5) — showing faith persisting through unresolved suffering.'),
('Psalms', 13, 'adults', 3, 'What does "lighten mine eyes" in Psalm 13:3 mean in the context of the psalm?', 'Give me physical sight', 'Restore life, vitality, and hope — eyes dimming was associated with approaching death in Hebrew thought', 'Enlighten my mind with wisdom', 'Remove my tears', 'a', 'Lighten mine eyes, lest I sleep the sleep of death (Psalm 13:3) — in Hebrew thought, bright eyes signified life and health; dimming eyes signified death.'),
('Psalms', 13, 'adults', 4, 'Why is David concerned about his enemies rejoicing if God does not help in Psalm 13:4?', 'For his own pride''s sake', 'Because the enemy''s triumph would be a public dishonour to God''s faithfulness and David''s trust in him', 'Because he fears physical harm', 'Because he wants to be famous', 'a', 'Lest mine enemy say, I have prevailed...lest those that trouble me rejoice when I am moved (Psalm 13:4) — enemy triumph is a reproach to God''s honour.'),
('Psalms', 13, 'adults', 5, 'What does the brevity of Psalm 13 (six verses) teach about the nature of lament?', 'Short psalms are less important', 'Even the briefest, most compressed cry of despair addressed to God is a complete and legitimate prayer', 'The psalm was never finished', 'Short psalms are for beginners', 'a', 'Psalm 13 is one of the shortest psalms, yet it contains the full arc of lament, petition, and praise — showing that brevity does not diminish authenticity.'),
('Psalms', 13, 'adults', 6, 'What does David''s appeal to "thy mercy" in Psalm 13:5 reveal about the grounds of his confidence?', 'His own righteousness', 'God''s hesed — covenant lovingkindness — not David''s merit', 'His past obedience', 'His royal status', 'a', 'But I have trusted in thy mercy (Psalm 13:5) — the Hebrew word is hesed, God''s covenant steadfast love, which is the true basis of David''s hope.'),
('Psalms', 13, 'adults', 7, 'How does Psalm 13 model praying honestly to God even in anger and despair?', 'It shows God disapproves of emotional prayer', 'It demonstrates that raw, unfiltered honesty before God is itself an act of faith — turning toward God rather than away', 'It teaches that complaint is sinful', 'It shows prayer must always end in praise to be valid', 'a', 'The fourfold "How long?" (Psalm 13:1-2) shows that authentic faith includes bringing unfiltered anguish to God, not suppressing it.'),
('Psalms', 13, 'adults', 8, 'How does the final "he hath dealt bountifully with me" in Psalm 13:6 function in relation to the current suffering described?', 'It proves the suffering is over', 'It is a proleptic or anticipatory statement of faith — David declares God''s bounty before seeing its fulfilment', 'It refers to past deliverances only', 'It contradicts the lament', 'a', 'I will sing unto the LORD, because he hath dealt bountifully with me (Psalm 13:6) — declared in the present tense as a faith statement before physical deliverance arrives.');

-- ═══ Psalms Chapter 14 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 14, 'kids', 1, 'What does the fool say in his heart in Psalm 14?', 'There is no God', 'I am stronger than God', 'God does not see me', 'I will not worship God', 'a', 'The fool hath said in his heart, There is no God (Psalm 14:1).'),
('Psalms', 14, 'kids', 2, 'Who does David say has gone aside and become filthy?', 'They are all gone aside; there is none that doeth good', 'Only the Gentiles', 'Only the wicked rulers', 'Only those who hate God', 'a', 'They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one (Psalm 14:3).'),
('Psalms', 14, 'kids', 3, 'What does David call the LORD in Psalm 14:6?', 'The refuge of the poor', 'The God of the righteous', 'The judge of all', 'The king of Israel', 'a', 'The LORD is his refuge (Psalm 14:6).'),
-- Teens
('Psalms', 14, 'teens', 1, 'What does God look down from heaven to see?', 'If there are any that understand and seek after God', 'If the temple is standing', 'If Israel obeys the law', 'If the sacrifices are correct', 'a', 'The LORD looked down from heaven upon the children of men, to see if there were any that did understand, and seek God (Psalm 14:2).'),
('Psalms', 14, 'teens', 2, 'What is God''s verdict on mankind in Psalm 14:3?', 'They are altogether become filthy; none doeth good, no, not one', 'Most are righteous but a few are evil', 'Only the nations are corrupt', 'The wise few remain faithful', 'a', 'They are all gone aside, they are all together become filthy: there is none that doeth good, no, not one (Psalm 14:3).'),
('Psalms', 14, 'teens', 3, 'What do the workers of iniquity do to God''s people according to Psalm 14:4?', 'Eat up my people as they eat bread', 'Fight against God''s people', 'Steal from God''s people', 'Mock and shame God''s people', 'a', 'Have all the workers of iniquity no knowledge? who eat up my people as they eat bread (Psalm 14:4).'),
('Psalms', 14, 'teens', 4, 'What sudden fear comes upon the workers of iniquity in Psalm 14:5?', 'Great fear where no fear was', 'A vision of judgment', 'The voice of God in thunder', 'The armies of Israel', 'a', 'There were they in great fear: for God is in the generation of the righteous (Psalm 14:5).'),
('Psalms', 14, 'teens', 5, 'What does David long for at the end of Psalm 14?', 'Oh that the salvation of Israel were come out of Zion!', 'A great victory over enemies', 'A new temple to be built', 'The return of the ark', 'a', 'Oh that the salvation of Israel were come out of Zion! when the LORD bringeth back the captivity of his people, Jacob shall rejoice, and Israel shall be glad (Psalm 14:7).'),
-- Adults
('Psalms', 14, 'adults', 1, 'In what New Testament passage does Paul use Psalm 14:1-3 to demonstrate universal human sinfulness?', 'John 3:16', 'Romans 3:10-12', 'Galatians 3:22', 'Ephesians 2:1', 'a', 'Paul quotes Psalm 14:1-3 in Romans 3:10-12 — "There is none righteous, no, not one" — as part of his argument for universal sin.'),
('Psalms', 14, 'adults', 2, 'What is the Hebrew word translated "fool" in Psalm 14:1, and what does it connote?', 'Kesil — a stupid person', 'Nabal — a morally corrupt person who has rejected God', 'Evil — a sinful person', 'Sakhal — a foolish person', 'a', 'The Hebrew word is Nabal — not intellectual stupidity but moral corruption, the wilful rejection of God''s authority (Psalm 14:1).'),
('Psalms', 14, 'adults', 3, 'What is the difference between Psalm 14 and Psalm 53?', 'Psalm 14 is shorter', 'They are nearly identical — Psalm 14 uses the covenant name LORD (YHWH) while Psalm 53 uses Elohim', 'Psalm 14 is a lament; Psalm 53 is a praise', 'Psalm 53 adds more verses', 'a', 'Psalms 14 and 53 are nearly identical, with the primary difference being that Psalm 14 uses YHWH while Psalm 53 uses Elohim — reflecting different liturgical collections.'),
('Psalms', 14, 'adults', 4, 'What is the significance of the phrase "no, not one" in Psalm 14:3?', 'It is an exaggeration for effect', 'It is an absolute, universal statement — no human being by nature seeks God or does good', 'It excludes the prophets and priests', 'It refers only to Gentile nations', 'a', '"There is none that doeth good, no, not one" (Psalm 14:3) — the emphatic double negative underlines the universal reach of human depravity.'),
('Psalms', 14, 'adults', 5, 'What does the eating of God''s people "as bread" in Psalm 14:4 illustrate?', 'The wicked are hungry', 'The casual, habitual nature of the wicked''s oppression — as routine and unremarkable to them as eating daily bread', 'The wicked are powerful warriors', 'The wicked perform religious meals', 'a', 'Who eat up my people as they eat bread (Psalm 14:4) — the simile shows oppression has become as routine and natural as the daily act of eating.'),
('Psalms', 14, 'adults', 6, 'What does it mean that the workers of iniquity "call not upon the LORD" in Psalm 14:4?', 'They pray to other gods', 'Practical atheism — their lives and actions function as though God does not exist, regardless of verbal belief', 'They are silent in prayer', 'They are illiterate and cannot pray', 'a', '"They call not upon the LORD" (Psalm 14:4) — the fool''s "no God" of verse 1 is practical atheism expressed in the refusal to pray or acknowledge God.'),
('Psalms', 14, 'adults', 7, 'What does the phrase "the LORD is his refuge" in Psalm 14:6 contrast with the wicked''s practical atheism?', 'The poor man has no other refuge', 'While the wicked deny God, the poor man has made God his refuge — faith and poverty together as a contrasting portrait', 'The righteous have no need of prayer', 'The poor are always righteous', 'a', 'Ye have shamed the counsel of the poor, because the LORD is his refuge (Psalm 14:6) — the poor believer''s faith-refuge contrasts with the wicked''s God-denial.'),
('Psalms', 14, 'adults', 8, 'How does the Messianic hope of Psalm 14:7 connect to Paul''s argument in Romans 3?', 'It has no connection to Paul', 'Paul''s quotation of Psalm 14 in Romans 3 is resolved only in the gospel — the salvation coming out of Zion is Jesus Christ, the only answer to universal sin', 'Paul contradicts Psalm 14''s hope', 'The Messianic hope is only for Israel', 'a', 'Psalm 14:7 hopes for salvation from Zion; Paul''s use of Psalm 14 in Romans 3 is resolved in Christ — the gospel is the salvation from Zion come to all (Romans 3:21-26).');

-- ═══ Psalms Chapter 15 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 15, 'kids', 1, 'What question does Psalm 15 begin with?', 'Who shall abide in thy tabernacle?', 'Who is the greatest in the kingdom?', 'Who can enter heaven?', 'Who shall see God''s face?', 'a', 'LORD, who shall abide in thy tabernacle? who shall dwell in thy holy hill? (Psalm 15:1).'),
('Psalms', 15, 'kids', 2, 'What does the person who abides with God do with the truth?', 'He speaketh the truth in his heart', 'He writes it on scrolls', 'He teaches it to children', 'He declares it in the temple', 'a', 'He that walketh uprightly, and worketh righteousness, and speaketh the truth in his heart (Psalm 15:2).'),
('Psalms', 15, 'kids', 3, 'What does the upright man NOT do to his neighbour?', 'He doeth not evil to his neighbour', 'He does not loan money', 'He does not compete with his neighbour', 'He does not speak to his neighbour', 'a', 'He that doeth not evil to his neighbour (Psalm 15:3).'),
-- Teens
('Psalms', 15, 'teens', 1, 'What does the upright person do when he swears an oath, even to his own hurt?', 'He changeth not', 'He breaks it if necessary', 'He renegotiates it', 'He seeks release from it', 'a', 'He that sweareth to his own hurt, and changeth not (Psalm 15:4).'),
('Psalms', 15, 'teens', 2, 'What does the person abiding on God''s holy hill NOT do with his money?', 'He putteth not out his money to usury', 'He does not spend it on pleasure', 'He does not save too much', 'He does not give it to the temple', 'a', 'He that putteth not out his money to usury, nor taketh reward against the innocent (Psalm 15:5).'),
('Psalms', 15, 'teens', 3, 'What does the God-fearer do regarding vile persons versus those who fear God?', 'He despises a vile person and honours them that fear the LORD', 'He treats all people equally', 'He avoids vile persons only in the temple', 'He rebukes all evil doers publicly', 'a', 'In whose eyes a vile person is contemned; but he honoureth them that fear the LORD (Psalm 15:4).'),
('Psalms', 15, 'teens', 4, 'Who does the upright man honour and who does he despise?', 'He honours them that fear the LORD and despises a vile person', 'He honours the king and despises the poor', 'He honours the priests and despises sinners', 'He honours the wise and despises fools', 'a', 'In whose eyes a vile person is contemned; but he honoureth them that fear the LORD (Psalm 15:4).'),
('Psalms', 15, 'teens', 5, 'What promise does Psalm 15 end with for the person who does these things?', 'He shall never be moved', 'He shall live forever', 'He shall rule over the nations', 'He shall receive great blessings', 'a', 'He that doeth these things shall never be moved (Psalm 15:5).'),
-- Adults
('Psalms', 15, 'adults', 1, 'How does Psalm 15 function as a "Torah liturgy" in its original temple context?', 'It was only for priests', 'It was likely used as an entrance liturgy — a question and answer about the moral qualifications required to approach God in worship', 'It was sung during harvest festivals', 'It was a psalm for private devotion only', 'a', 'Psalm 15 is an entrance liturgy or "Torah liturgy" — the question in verse 1 represents the entering worshipper, and verses 2-5 give the moral answer to who may approach God.'),
('Psalms', 15, 'adults', 2, 'How do the ethical requirements of Psalm 15 relate to the Ten Commandments?', 'They are completely different', 'The ethical qualities of Psalm 15 are largely a positive restatement of the second table of the Ten Commandments applied to social life', 'Psalm 15 replaces the Ten Commandments', 'The Ten Commandments are not related to Psalm 15', 'a', 'The moral portrait of Psalm 15 — truth, justice, no slander, no bribery — reflects the second table of the Decalogue applied to neighbour relationships.'),
('Psalms', 15, 'adults', 3, 'What does "backbiteth not with his tongue" in Psalm 15:3 guard against?', 'Flattery', 'Secret slander and gossip that undermines a person''s reputation in their absence', 'Public insult', 'Speaking too much', 'a', 'He that backbiteth not with his tongue, nor doeth evil to his neighbour (Psalm 15:3) — backbiting is secret slander, speaking evil of someone behind their back.'),
('Psalms', 15, 'adults', 4, 'What is the moral significance of the clause "he that sweareth to his own hurt, and changeth not" in Psalm 15:4?', 'Oaths should never be made', 'Integrity requires keeping commitments even when it is costly to do so', 'Oaths are only binding if witnessed', 'Promises should be renegotiated when circumstances change', 'a', 'He that sweareth to his own hurt, and changeth not (Psalm 15:4) — the mark of integrity is keeping one''s word even at personal cost.'),
('Psalms', 15, 'adults', 5, 'What is the prohibition against usury in Psalm 15:5 and what is its social context?', 'All interest on any money is forbidden', 'Charging interest on loans to the poor was forbidden in the Mosaic law (Exodus 22:25) — Psalm 15:5 applies this to the character of the righteous', 'Only loans to foreigners could bear interest', 'Banking was entirely forbidden in Israel', 'a', 'He that putteth not out his money to usury (Psalm 15:5) — usury (interest on loans to poor Israelites) was forbidden in Exodus 22:25, reflecting God''s concern for economic justice.'),
('Psalms', 15, 'adults', 6, 'How does Psalm 15 answer the question of access to God differently from ritual purity laws?', 'It emphasises ritual purity over ethics', 'It shifts the focus entirely to moral and ethical integrity — it is character, not ritual status, that defines who may approach God', 'It requires sacrifices before entry', 'It requires priestly lineage', 'a', 'Psalm 15 answers the question of access to God entirely in ethical, not ritual, terms — integrity, truth, justice — a radical emphasis on moral character.'),
('Psalms', 15, 'adults', 7, 'What does "nor taketh reward against the innocent" in Psalm 15:5 condemn?', 'Tithing to the temple', 'Taking bribes to pervert justice against an innocent person', 'Accepting gifts of any kind', 'Charging fees for teaching the law', 'a', 'Nor taketh reward against the innocent (Psalm 15:5) — this condemns bribery in the judicial system, a major concern of the prophets (cf. Isaiah 1:23, Amos 5:12).'),
('Psalms', 15, 'adults', 8, 'What does the conclusion "he shall never be moved" in Psalm 15:5 promise, and what does it echo throughout the Psalter?', 'Material prosperity', 'Unshakeable stability and security in God — echoing the stability of the righteous man of Psalm 1 and the trust-theme throughout the Psalter', 'Physical immortality', 'Permanent residence in Jerusalem', 'a', 'He that doeth these things shall never be moved (Psalm 15:5) — the "not moved" promise echoes Psalm 1:3 and recurs throughout the Psalter.');

-- ═══ Psalms Chapter 16 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 16, 'kids', 1, 'Where does David say he has a goodly heritage in Psalm 16?', 'The lines are fallen unto me in pleasant places', 'In the hills of Judah', 'In the city of Jerusalem', 'In the house of the LORD', 'a', 'The lines are fallen unto me in pleasant places; yea, I have a goodly heritage (Psalm 16:6).'),
('Psalms', 16, 'kids', 2, 'What does David say God will not leave his soul in?', 'Hell', 'The grave', 'Darkness', 'Danger', 'a', 'For thou wilt not leave my soul in hell; neither wilt thou suffer thine Holy One to see corruption (Psalm 16:10).'),
('Psalms', 16, 'kids', 3, 'What does David say is at God''s right hand?', 'Pleasures for evermore', 'Riches and honour', 'Wisdom and strength', 'Peace and rest', 'a', 'At thy right hand there are pleasures for evermore (Psalm 16:11).'),
-- Teens
('Psalms', 16, 'teens', 1, 'What does David say about the LORD being always before him in Psalm 16:8?', 'He shall not be moved', 'He loses his way', 'He becomes discouraged', 'He rests from work', 'a', 'I have set the LORD always before me: because he is at my right hand, I shall not be moved (Psalm 16:8).'),
('Psalms', 16, 'teens', 2, 'What does David''s heart do and what is glad according to Psalm 16:9?', 'My heart is glad, and my glory rejoiceth: my flesh also shall rest in hope', 'His heart faints with fear', 'His heart breaks with sorrow', 'His heart leaps for joy in battle', 'a', 'Therefore my heart is glad, and my glory rejoiceth: my flesh also shall rest in hope (Psalm 16:9).'),
('Psalms', 16, 'teens', 3, 'What does David call the LORD in Psalm 16:2?', 'O my soul, thou hast said, Thou art my Lord', 'My rock and my shield', 'My shepherd and guide', 'My tower and fortress', 'a', 'O my soul, thou hast said unto the LORD, Thou art my Lord: my goodness extendeth not to thee (Psalm 16:2).'),
('Psalms', 16, 'teens', 4, 'What is the path of life associated with in Psalm 16:11?', 'In thy presence is fulness of joy', 'In the house of the LORD', 'In the keeping of the law', 'In righteous living', 'a', 'Thou wilt shew me the path of life: in thy presence is fulness of joy (Psalm 16:11).'),
('Psalms', 16, 'teens', 5, 'What does David say about those who run after other gods in Psalm 16:4?', 'Their sorrows shall be multiplied', 'They shall be destroyed', 'They shall lose their heritage', 'They shall wander forever', 'a', 'Their sorrows shall be multiplied that hasten after another god (Psalm 16:4).'),
-- Adults
('Psalms', 16, 'adults', 1, 'In what two New Testament passages is Psalm 16:8-11 quoted, and by whom?', 'By Matthew and John', 'By Peter in Acts 2:25-28 and Paul in Acts 13:35 — both applying it to the resurrection of Christ', 'By Luke and Mark', 'By Paul in Romans and Hebrews', 'a', 'Peter quotes Psalm 16:8-11 in Acts 2:25-28 applying it to Christ''s resurrection; Paul quotes verse 10 in Acts 13:35 as evidence of Christ''s resurrection.'),
('Psalms', 16, 'adults', 2, 'What is the key argument Peter makes in Acts 2 about Psalm 16:10?', 'David wrote it about himself and was fulfilled in his own lifetime', 'David was a prophet and spoke of Christ''s resurrection — David himself saw corruption, but Christ did not', 'The psalm does not refer to the resurrection', 'David was predicting his own escape from death', 'a', 'Peter argues in Acts 2:29-31 that David died and saw corruption, so Psalm 16:10 — "neither wilt thou suffer thine Holy One to see corruption" — must refer to Christ.'),
('Psalms', 16, 'adults', 3, 'What is the title "Michtam of David" in the superscription thought to mean?', 'A song of the poor', 'Possibly "golden psalm" or a psalm of special value — the exact meaning is uncertain', 'A war song', 'A lament psalm', 'a', 'Michtam (Psalm 16 superscription) appears in six psalm titles (16, 56-60) and may mean "golden" or a psalm of special worth — the exact meaning is debated.'),
('Psalms', 16, 'adults', 4, 'What is David''s attitude toward the pagan sacrificial system in Psalm 16:4?', 'He is indifferent to it', 'He refuses to participate in their drink offerings of blood or take their names upon his lips', 'He mildly disapproves', 'He offers critique only of foreign nations'' practices', 'a', 'Their drink offerings of blood will I not offer, nor take up their names into my lips (Psalm 16:4) — David''s complete separation from pagan worship.'),
('Psalms', 16, 'adults', 5, 'What do "the lot" and "the lines" in Psalm 16:5-6 represent in the context of the land covenant?', 'David''s gambling habits', 'God as David''s divinely appointed inheritance and portion — using the language of the land allotment to Israel', 'A specific piece of land David owned', 'The royal treasury', 'a', 'The LORD is the portion of mine inheritance and of my cup: thou maintainest my lot. The lines are fallen unto me in pleasant places (Psalm 16:5-6) — land allotment language applied to God himself as portion.'),
('Psalms', 16, 'adults', 6, 'What does David mean by "my reins also instruct me in the night seasons" in Psalm 16:7?', 'He has nightmares', 'God''s counsel penetrates to his deepest inner being, even in sleep — the reins (kidneys) represent the seat of conscience', 'He reads the law at night', 'He receives angelic visions', 'a', 'My reins also instruct me in the night seasons (Psalm 16:7) — the reins (kidneys) in Hebrew thought were the seat of deep moral instruction and conscience.'),
('Psalms', 16, 'adults', 7, 'How does Psalm 16 bridge the individual experience of David and the corporate resurrection hope of Messiah?', 'It only concerns David personally', 'David''s personal experience of trust in God becomes prophetically applied to the Messiah''s death and resurrection by Peter and Paul', 'It is only about Israel as a nation', 'It has no prophetic dimension', 'a', 'Psalm 16 begins as David''s personal trust (vv.1-8), but Peter and Paul identify its ultimate fulfilment in Christ''s resurrection — a typological bridge (Acts 2:25-28; 13:35).'),
('Psalms', 16, 'adults', 8, 'What is the climactic promise of Psalm 16:11?', 'Promise of material prosperity', 'The path of life, fulness of joy in God''s presence, and pleasures forevermore — the ultimate resolution of the soul''s longing for God', 'Promise of long earthly life', 'Promise of victory over enemies', 'a', 'Thou wilt shew me the path of life: in thy presence is fulness of joy; at thy right hand there are pleasures for evermore (Psalm 16:11).');

-- ═══ Psalms Chapter 17 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 17, 'kids', 1, 'What does David ask God to keep him as in Psalm 17?', 'The apple of the eye', 'The lamb of the flock', 'The light of the world', 'The joy of the heart', 'a', 'Keep me as the apple of the eye, hide me under the shadow of thy wings (Psalm 17:8).'),
('Psalms', 17, 'kids', 2, 'What will David see when he wakes up?', 'God''s likeness', 'God''s glory', 'God''s angels', 'God''s kingdom', 'a', 'As for me, I will behold thy face in righteousness: I shall be satisfied, when I awake, with thy likeness (Psalm 17:15).'),
('Psalms', 17, 'kids', 3, 'Where does David ask God to hide him?', 'Under the shadow of thy wings', 'In the mountain fortress', 'In the depths of the earth', 'In the holy tabernacle', 'a', 'Hide me under the shadow of thy wings (Psalm 17:8).'),
-- Teens
('Psalms', 17, 'teens', 1, 'What does David ask God to hear in Psalm 17:1?', 'A just cause, my cry, and my prayer that goeth not out of feigned lips', 'His songs of praise', 'His plans for the temple', 'His confession of sin', 'a', 'Hear the right, O LORD, attend unto my cry, give ear unto my prayer, that goeth not out of feigned lips (Psalm 17:1).'),
('Psalms', 17, 'teens', 2, 'What test does David invite God to perform in Psalm 17:3?', 'Thou hast proved mine heart; thou hast visited me in the night', 'Examine my deeds and my words', 'Look at my offerings and my sacrifices', 'Count my enemies and my prayers', 'a', 'Thou hast proved mine heart; thou hast visited me in the night; thou hast tried me, and shalt find nothing (Psalm 17:3).'),
('Psalms', 17, 'teens', 3, 'What do the enemies encircle David like in Psalm 17:12?', 'A lion that is greedy of his prey', 'A pack of wolves', 'A swarm of bees', 'A raging fire', 'a', 'Like as a lion that is greedy of his prey, and as it were a young lion lurking in secret places (Psalm 17:12).'),
('Psalms', 17, 'teens', 4, 'What do the wicked have in this life according to Psalm 17:14?', 'Their portion in this life and whose belly thou fillest with thy hid treasure', 'Great wisdom and glory', 'Peace and long life', 'Victory in every battle', 'a', 'Men of the world, which have their portion in this life, and whose belly thou fillest with thy hid treasure (Psalm 17:14).'),
('Psalms', 17, 'teens', 5, 'What does David say his steps have done in Psalm 17:5?', 'Held fast to God''s paths and not slipped', 'Wandered far from God', 'Led him into the wilderness', 'Brought him to the house of the LORD', 'a', 'Hold up my goings in thy paths, that my footsteps slip not (Psalm 17:5).'),
-- Adults
('Psalms', 17, 'adults', 1, 'What is the title of Psalm 17 in the KJV, and what does "A Prayer of David" indicate?', 'A Michtam — a golden poem', 'It is one of the few psalms explicitly titled "A Prayer" — indicating a direct petition to God rather than praise or meditation', 'A Shiggaion — a wild ode', 'A Maschil — an instructional poem', 'a', 'Psalm 17 is titled "A Prayer of David" — one of five explicitly prayer-titled psalms (17, 86, 90, 102, 142), emphasizing direct petition.'),
('Psalms', 17, 'adults', 2, 'What does "that goeth not out of feigned lips" in Psalm 17:1 add to David''s petition?', 'That his prayer is poetically composed', 'That his prayer is utterly sincere — not hypocritical or performed for human approval', 'That he is speaking quietly', 'That he wrote the prayer in advance', 'a', 'Give ear unto my prayer, that goeth not out of feigned lips (Psalm 17:1) — David appeals to God on the basis of the utter sincerity of his prayer.'),
('Psalms', 17, 'adults', 3, 'What is the "apple of the eye" in Psalm 17:8 as a cultural and anatomical expression?', 'A fruit offering', 'The pupil — the most sensitive and protected part of the eye, used as a metaphor for that which is most precious and carefully guarded', 'The eye of God himself', 'A jewel worn over the eye', 'a', 'Keep me as the apple of the eye (Psalm 17:8) — the "apple" (Hebrew: iyshon, little man) refers to the pupil, the most carefully protected part of the body.'),
('Psalms', 17, 'adults', 4, 'What does the "shadow of thy wings" imagery in Psalm 17:8 evoke?', 'A building with a roof', 'The protective wings of the cherubim over the ark and the mother bird sheltering her young — divine protection and tender care', 'Storm clouds', 'The wings of an eagle carrying Israel', 'a', 'Hide me under the shadow of thy wings (Psalm 17:8) — evoking both the cherubim wings over the ark (Exodus 25:20) and the mother bird protecting her young (cf. Psalm 91:4).'),
('Psalms', 17, 'adults', 5, 'How does David''s protestation of innocence in Psalm 17:3-5 relate to the legal context of the psalm?', 'It is arrogant self-righteousness', 'In the context of false accusations, David appeals to his proven integrity as the basis for God''s vindication — it is a legal declaration of innocence before the divine judge', 'It shows David was sinless', 'It contradicts Psalm 51', 'a', 'Thou hast proved mine heart...thou hast tried me, and shalt find nothing (Psalm 17:3) — a legal declaration of innocence before God as judge in the face of false accusation.'),
('Psalms', 17, 'adults', 6, 'What contrast does Psalm 17:14-15 draw between the destiny of the wicked and the righteous?', 'The wicked suffer now and the righteous prosper now', 'The wicked have their portion in this life; the righteous will be satisfied with God''s likeness at the resurrection', 'Both receive earthly rewards', 'The righteous receive more earthly goods', 'a', 'The wicked have their portion in this life (v.14), but David will be satisfied with thy likeness at the awakening (v.15) — a profound contrast of temporal versus eternal destiny.'),
('Psalms', 17, 'adults', 7, 'What does "I shall be satisfied, when I awake, with thy likeness" in Psalm 17:15 anticipate theologically?', 'A good night''s sleep', 'The resurrection — the ultimate satisfaction of seeing God''s face and being transformed into his likeness', 'A morning prayer', 'Physical healing', 'a', 'I shall be satisfied, when I awake, with thy likeness (Psalm 17:15) — widely understood as pointing to the resurrection and final vision of God (cf. 1 John 3:2).'),
('Psalms', 17, 'adults', 8, 'Why does David say "from men which are thy hand" in Psalm 17:14, and what is the theological implication?', 'He is asking to be saved from angels', 'Even the wicked enemies who threaten him are instruments in God''s sovereign hand — so God can restrain them', 'He is asking for deliverance from the king''s soldiers', 'He is asking God to use human helpers', 'a', 'Deliver my soul from the wicked, which is thy sword: from men which are thy hand (Psalm 17:13-14) — even enemies are God''s instruments, and God can withdraw their power.');

-- ═══ Psalms Chapter 18 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 18, 'kids', 1, 'What does David call the LORD at the very start of Psalm 18?', 'My strength', 'My shepherd', 'My light', 'My refuge', 'a', 'I will love thee, O LORD, my strength (Psalm 18:1).'),
('Psalms', 18, 'kids', 2, 'What does David say about God''s way in Psalm 18:30?', 'As for God, his way is perfect', 'God''s way is straight', 'God''s way is good', 'God''s way is bright', 'a', 'As for God, his way is perfect: the word of the LORD is tried (Psalm 18:30).'),
('Psalms', 18, 'kids', 3, 'What does David say God makes his feet like?', 'Hinds'' feet', 'Eagle''s wings', 'Lion''s paws', 'Iron hooves', 'a', 'He maketh my feet like hinds'' feet, and setteth me upon my high places (Psalm 18:33).'),
-- Teens
('Psalms', 18, 'teens', 1, 'What is the parallel passage to Psalm 18 found elsewhere in the Bible?', '2 Samuel 22', '1 Chronicles 16', 'Deuteronomy 32', 'Isaiah 12', 'a', 'Psalm 18 is nearly identical to the song in 2 Samuel 22, which David sang after God delivered him from all his enemies.'),
('Psalms', 18, 'teens', 2, 'With what did God come down when He rescued David from great enemies in Psalm 18?', 'Darkness, clouds, coals of fire, hailstones, and thunder', 'A rushing wind and bright light', 'Angels and heavenly armies', 'Fire and a still small voice', 'a', 'He bowed the heavens also, and came down: and darkness was under his feet...there went up a smoke out of his nostrils, and fire out of his mouth devoured (Psalm 18:9-12).'),
('Psalms', 18, 'teens', 3, 'How does David say God rewards the froward in Psalm 18:26?', 'Thou wilt shew thyself froward', 'He destroys them immediately', 'He ignores them', 'He turns them to his servants', 'a', 'With the froward thou wilt shew thyself froward (Psalm 18:26).'),
('Psalms', 18, 'teens', 4, 'What six names does David give the LORD in Psalm 18:2?', 'My rock, fortress, deliverer, God, strength, buckler', 'My shepherd, light, salvation, king, hope, joy', 'My fire, wind, thunder, rain, cloud, star', 'My sword, shield, spear, arrow, bow, wall', 'a', 'The LORD is my rock, and my fortress, and my deliverer; my God, my strength, in whom I will trust; my buckler, and the horn of my salvation, and my high tower (Psalm 18:2).'),
('Psalms', 18, 'teens', 5, 'What Messianic note does Psalm 18 close with regarding David''s seed?', 'He sheweth mercy to his anointed, to David, and to his seed for evermore', 'The seed of David shall rule all nations', 'The throne of David shall stand forever', 'The descendants of David will build the temple', 'a', 'He is the tower of salvation for his king: and sheweth mercy to his anointed, to David, and to his seed for evermore (Psalm 18:50).'),
-- Adults
('Psalms', 18, 'adults', 1, 'What is the historical context given in the superscription of Psalm 18?', 'David''s flight from Saul in the cave of Adullam', 'The day the LORD delivered David from the hand of all his enemies and from the hand of Saul', 'David''s victory over the Philistines at the valley of Elah', 'David''s prayer upon his coronation as king', 'a', 'The superscription states: "A Psalm of David...in the day that the LORD delivered him from the hand of all his enemies, and from the hand of Saul."'),
('Psalms', 18, 'adults', 2, 'What does "the cords of death compassed me" in Psalm 18:4-5 signify?', 'A physical entanglement', 'The Hebrew word (hebel — cord/snare) suggests the inescapable grip of death surrounding David like hunting nets', 'A rope used in torture', 'Chains of imprisonment', 'a', 'The sorrows of death compassed me...the snares of death prevented me (Psalm 18:4-5) — hebel (cords) and snares evoke the inescapable entrapment of approaching death.'),
('Psalms', 18, 'adults', 3, 'What literary device is used in Psalm 18:9-15 when God descends to rescue David?', 'A simple narrative', 'A theophany — a dramatic description of God''s self-manifestation using storm imagery (darkness, fire, lightning, thunder) as in Sinai', 'A dream vision', 'A historical account', 'a', 'Psalm 18:9-15 is a theophany — God''s dramatic appearance using cosmic storm imagery echoing the Sinai theophany of Exodus 19.'),
('Psalms', 18, 'adults', 4, 'What does the phrase "with the pure thou wilt shew thyself pure" in Psalm 18:26 teach about God''s moral responsiveness?', 'God imitates human behaviour mechanically', 'God''s dealings with people mirror their own moral disposition — the pure experience his purity, the froward experience his opposition', 'God rewards only outward purity', 'God changes his character based on human sin', 'a', 'Psalm 18:25-26 teaches divine moral responsiveness — God relates to the merciful with mercy, the pure with purity, and the froward with opposition.'),
('Psalms', 18, 'adults', 5, 'What does "thou wilt save the afflicted people; but wilt bring down high looks" in Psalm 18:27 express?', 'God favours the poor over the rich', 'The consistent biblical pattern of divine reversal — the humble are exalted and the proud are brought low', 'God despises the proud for their appearance', 'The afflicted always deserve salvation', 'a', 'Thou wilt save the afflicted people; but wilt bring down high looks (Psalm 18:27) — the reversal theme central to biblical theology (cf. Luke 1:51-53, James 4:6).'),
('Psalms', 18, 'adults', 6, 'What does Paul quote from Psalm 18:49 in Romans 15:9, and why?', 'To prove David was a prophet', 'To show that Gentile praise was prophesied in the Old Testament — David''s praise among the nations foreshadows Gentile inclusion', 'To prove the resurrection', 'To establish David''s authority', 'a', 'Paul quotes Psalm 18:49 — "I will give praise unto thee among the Gentiles" — in Romans 15:9 as scriptural support for the Gentile mission.'),
('Psalms', 18, 'adults', 7, 'What does "enlarged my steps under me" in Psalm 18:36 mean?', 'God gave David longer legs', 'God expanded the secure footing available to David — preventing stumbling in dangerous terrain, metaphorically and literally', 'God gave David more territory', 'God provided David with better sandals', 'a', 'Thou hast enlarged my steps under me, that my feet did not slip (Psalm 18:36) — enlarging one''s steps means giving secure footing, preventing stumbling.'),
('Psalms', 18, 'adults', 8, 'How does Psalm 18 close with a Messianic note regarding the house of David?', 'With a prayer for Solomon', 'David declares God''s great deliverance to his king and his seed for evermore — pointing to the Davidic covenant and its Messianic fulfilment', 'With a praise for the nation of Israel', 'With a prediction of the temple', 'a', 'He is the tower of salvation for his king: and sheweth mercy to his anointed, to David, and to his seed for evermore (Psalm 18:50) — pointing to the Davidic covenant and its Messianic line.');

-- ═══ Psalms Chapter 19 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 19, 'kids', 1, 'What do the heavens declare in Psalm 19?', 'The glory of God', 'The power of the angels', 'The wisdom of men', 'The beauty of creation', 'a', 'The heavens declare the glory of God; and the firmament sheweth his handywork (Psalm 19:1).'),
('Psalms', 19, 'kids', 2, 'What is the law of the LORD sweeter than according to Psalm 19?', 'Honey and the honeycomb', 'Richer than gold', 'Brighter than the sun', 'Purer than silver', 'a', 'More to be desired are they than gold, yea, than much fine gold: sweeter also than honey and the honeycomb (Psalm 19:10).'),
('Psalms', 19, 'kids', 3, 'What does David ask God to cleanse him from at the end of Psalm 19?', 'Secret faults', 'Open sins', 'All wickedness', 'Pride and anger', 'a', 'Cleanse thou me from secret faults (Psalm 19:12).'),
-- Teens
('Psalms', 19, 'teens', 1, 'What does day utter to day and night to night according to Psalm 19?', 'Knowledge', 'Songs of praise', 'The times and seasons', 'The history of creation', 'a', 'Day unto day uttereth speech, and night unto night sheweth knowledge (Psalm 19:2).'),
('Psalms', 19, 'teens', 2, 'The sun is compared to what two things in Psalm 19:5?', 'A bridegroom and a strong man to run a race', 'A fire and a swift bird', 'A king and a warrior', 'A lamp and a torch', 'a', 'Which is as a bridegroom coming out of his chamber, and rejoiceth as a strong man to run a race (Psalm 19:5).'),
('Psalms', 19, 'teens', 3, 'What six terms does David use for God''s word in Psalm 19:7-9?', 'Law, testimony, statutes, commandment, fear, judgments', 'Word, precept, decree, covenant, promise, blessing', 'Truth, wisdom, light, life, peace, joy', 'Commandment, law, word, saying, oracle, voice', 'a', 'The law of the LORD, the testimony of the LORD, the statutes of the LORD, the commandment of the LORD, the fear of the LORD, the judgments of the LORD (Psalm 19:7-9).'),
('Psalms', 19, 'teens', 4, 'What does David pray would be acceptable in God''s sight in Psalm 19:14?', 'The words of my mouth, and the meditation of my heart', 'His offerings and sacrifices', 'His deeds and his ways', 'His prayers and his songs', 'a', 'Let the words of my mouth, and the meditation of my heart, be acceptable in thy sight, O LORD, my strength, and my redeemer (Psalm 19:14).'),
('Psalms', 19, 'teens', 5, 'What does David say "there is no speech nor language" about in Psalm 19:3?', 'Their voice is not heard', 'There is no place where their voice is not heard', 'Their language is unknown', 'Men cannot understand it', 'a', 'There is no speech nor language, where their voice is not heard (Psalm 19:3).'),
-- Adults
('Psalms', 19, 'adults', 1, 'How does Psalm 19 divide into two major parts, and what theme unites them?', 'No divisions exist — it is one continuous poem', 'Part 1 (vv.1-6) is general revelation through creation; Part 2 (vv.7-14) is special revelation through the law — both are God''s self-disclosure', 'Part 1 is lament; Part 2 is praise', 'Part 1 is about David; Part 2 is about Israel', 'a', 'Psalm 19 divides into creation revelation (vv.1-6) and word revelation (vv.7-14), united by the theme of God''s self-disclosure in nature and Scripture.'),
('Psalms', 19, 'adults', 2, 'What does "there is no speech nor language, where their voice is not heard" in Psalm 19:3 teach about general revelation?', 'The heavens literally speak in all languages', 'Creation''s witness transcends all linguistic and cultural barriers — it is universal and without excuse', 'The heavens speak only to believers', 'Creation''s voice requires interpretation by priests', 'a', 'There is no speech nor language, where their voice is not heard (Psalm 19:3) — creation''s testimony to God is universal, forming the basis of Paul''s argument in Romans 1:20.'),
('Psalms', 19, 'adults', 3, 'How does Paul allude to Psalm 19:4 in Romans 10:18?', 'To prove creation is beautiful', 'He applies the worldwide reach of creation''s testimony to the worldwide reach of the gospel — "their sound went into all the earth"', 'To prove angels preach the gospel', 'To prove the law was universal', 'a', 'Paul quotes "their sound went into all the earth" (Psalm 19:4) in Romans 10:18 to argue that the gospel, like creation''s voice, has gone into all the world.'),
('Psalms', 19, 'adults', 4, 'What six pairs of quality-and-effect are described for God''s word in Psalm 19:7-9?', 'Six synonyms for the law with no associated effects', 'Perfect (converting the soul), sure (making wise the simple), right (rejoicing the heart), pure (enlightening the eyes), clean (enduring for ever), true and righteous altogether', 'Holy, mighty, eternal, good, gracious, powerful', 'Faithful, true, just, merciful, righteous, perfect', 'a', 'Psalm 19:7-9 lists six pairs: law=perfect/converting soul, testimony=sure/wise simple, statutes=right/rejoicing heart, commandment=pure/enlightening eyes, fear=clean/enduring, judgments=true/righteous.'),
('Psalms', 19, 'adults', 5, 'What is the theological significance of the law being "more to be desired than gold" and "sweeter than honey" in Psalm 19:10?', 'Material wealth and sweet food should be avoided', 'God''s word surpasses the highest material value (gold) and the greatest sensory pleasure (honey) — it is the supreme desirable of life', 'The psalmist is describing a literal reward for obedience', 'The law was written on gold tablets', 'a', 'More to be desired are they than gold...sweeter also than honey and the honeycomb (Psalm 19:10) — two superlatives establishing God''s word as life''s supreme treasure.'),
('Psalms', 19, 'adults', 6, 'What does "Who can understand his errors? cleanse thou me from secret faults" in Psalm 19:12 teach about human moral awareness?', 'David was unusually sinful', 'Human beings cannot fully perceive the depth of their own sin — God''s law exposes faults hidden even from one''s own self-awareness', 'Secret sins are unforgivable', 'David had committed specific hidden crimes', 'a', 'Who can understand his errors? cleanse thou me from secret faults (Psalm 19:12) — the law''s perfect standard reveals sins the conscience did not register.'),
('Psalms', 19, 'adults', 7, 'What are "presumptuous sins" in Psalm 19:13, and why does David specifically pray against them?', 'Minor sins committed accidentally', 'Deliberate, high-handed, wilful rebellion — sins committed with a raised fist against God''s known will', 'Sins committed in ignorance', 'Sins of sexual immorality', 'a', 'Keep back thy servant also from presumptuous sins; let them not have dominion over me (Psalm 19:13) — presumptuous sins are wilful, deliberate transgressions that lead to moral domination.'),
('Psalms', 19, 'adults', 8, 'What does David call God in the final verse of Psalm 19:14, and what is the significance of this closing title?', 'LORD of hosts', 'My strength and my redeemer — joining the power to sustain with the grace to redeem as the twin grounds of the prayer', 'The holy one of Israel', 'My rock and my fortress', 'a', '"O LORD, my strength, and my redeemer" (Psalm 19:14) — tsuri (my rock/strength) with go''eli (my kinsman-redeemer), combining power and redemptive grace.');

-- ═══ Psalms Chapter 20 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 20, 'kids', 1, 'What does Psalm 20 ask God to do for the king in the day of trouble?', 'Hear him in the day of trouble', 'Give him great wisdom', 'Build him a great army', 'Make him live forever', 'a', 'The LORD hear thee in the day of trouble; the name of the God of Jacob defend thee (Psalm 20:1).'),
('Psalms', 20, 'kids', 2, 'What do some people trust in and what does David trust in?', 'Some trust in chariots and horses; we remember the name of the LORD', 'Some trust in gold; we trust in prayer', 'Some trust in armies; we trust in prophecy', 'Some trust in kings; we trust in God''s promises', 'a', 'Some trust in chariots, and some in horses: but we will remember the name of the LORD our God (Psalm 20:7).'),
('Psalms', 20, 'kids', 3, 'What does the psalm ask God to grant the king?', 'All his petitions', 'Great riches and honour', 'Victory in all battles', 'Long life and good health', 'a', 'The LORD fulfil all thy petitions (Psalm 20:5).'),
-- Teens
('Psalms', 20, 'teens', 1, 'From where does God send help according to Psalm 20:2?', 'From the sanctuary and Zion', 'From the heavens above', 'From the angel armies', 'From the holy mountain', 'a', 'Send thee help from the sanctuary, and strengthen thee out of Zion (Psalm 20:2).'),
('Psalms', 20, 'teens', 2, 'What does the congregation say they will do in the name of their God in Psalm 20:5?', 'We will rejoice in thy salvation and set up our banners', 'We will offer great sacrifices', 'We will sing new songs', 'We will march into battle', 'a', 'We will rejoice in thy salvation, and in the name of our God we will set up our banners (Psalm 20:5).'),
('Psalms', 20, 'teens', 3, 'What does the LORD remember according to Psalm 20:3?', 'All thy offerings, and accept thy burnt sacrifice', 'The prayers of his people', 'The sins of the wicked', 'The victories of Israel', 'a', 'Remember all thy offerings, and accept thy burnt sacrifice (Psalm 20:3).'),
('Psalms', 20, 'teens', 4, 'What happens to those who trust in chariots and horses?', 'They are brought down and fallen', 'They achieve great victories', 'They are scattered by God''s wind', 'They flee in panic', 'a', 'They are brought down and fallen: but we are risen, and stand upright (Psalm 20:8).'),
('Psalms', 20, 'teens', 5, 'What is the final petition of Psalm 20:9?', 'Save, LORD: let the king hear us when we call', 'Give victory to your servant the king', 'Arise and scatter our enemies', 'Send your angel before us into battle', 'a', 'Save, LORD: let the king hear us when we call (Psalm 20:9).'),
-- Adults
('Psalms', 20, 'adults', 1, 'What is the liturgical setting of Psalm 20, and how does its structure reflect that setting?', 'A private prayer of David', 'A royal pre-battle liturgy — a congregation prays for the king (vv.1-5), a priest or prophet declares divine assurance (vv.6-8), and a closing petition is made (v.9)', 'A thanksgiving psalm after victory', 'A coronation psalm for a new king', 'a', 'Psalm 20 is a royal pre-battle liturgy: congregational intercession (vv.1-5), a confident divine oracle (vv.6-8), and final petition (v.9).'),
('Psalms', 20, 'adults', 2, 'What does "the name of the God of Jacob defend thee" in Psalm 20:1 reveal about the concept of divine name in Israel?', 'It is a magical formula', 'The divine name represents God''s character, covenant, and power — invoking it is appealing to the full weight of God''s self-revealed identity and covenant promise', 'It is a title only for Jacob''s descendants', 'It is a liturgical phrase without specific meaning', 'a', 'The name of the God of Jacob (Psalm 20:1) — in Hebrew thought the divine name encapsulates God''s entire character and covenant faithfulness.'),
('Psalms', 20, 'adults', 3, 'What does "set up our banners" in Psalm 20:5 signify in the context of ancient Near Eastern warfare?', 'Decorating the temple', 'Raising military standards in the name of God — claiming victory and territory in God''s name rather than human military might', 'Making offerings to the LORD', 'Proclaiming a national holiday', 'a', 'In the name of our God we will set up our banners (Psalm 20:5) — military banners (standards) proclaimed ownership and victory in the name of one''s deity.'),
('Psalms', 20, 'adults', 4, 'How does Psalm 20:6 function as a divine oracle within the congregational prayer?', 'It is a later addition', 'It is a sudden shift from petition to confident assurance — "Now know I that the LORD saveth his anointed" — likely spoken by a priest or prophet', 'It is David speaking of himself', 'It is the king''s personal testimony', 'a', 'Now know I that the LORD saveth his anointed (Psalm 20:6) — a sudden first-person oracle of assurance, likely a priestly or prophetic response to the congregation''s prayer.'),
('Psalms', 20, 'adults', 5, 'What is the theological principle behind "some trust in chariots, and some in horses: but we will remember the name of the LORD" in Psalm 20:7?', 'That military preparation is sinful', 'That ultimate security rests not in military technology but in the covenant God — trust must be in the divine name, not in human power', 'That Israel never used military equipment', 'That chariots and horses are forbidden by the law', 'a', 'Some trust in chariots and some in horses (Psalm 20:7) — the contrast is not between preparation and laziness, but between ultimate trust in military power versus trust in the covenant God.'),
('Psalms', 20, 'adults', 6, 'How does the law of the king in Deuteronomy 17:16 relate to Psalm 20:7?', 'There is no connection', 'Deuteronomy 17:16 forbids the king from multiplying horses — Psalm 20:7 reflects this principle, grounding military security in God rather than cavalry', 'Deuteronomy contradicts Psalm 20', 'The law permits horses for the king only', 'a', 'Deuteronomy 17:16 warned the king not to multiply horses — Psalm 20:7''s contrast between trusting in horses versus the LORD''s name applies this principle liturgically.'),
('Psalms', 20, 'adults', 7, 'What does "his holy heaven" in Psalm 20:6 add to the theology of divine transcendence and immanence in the psalm?', 'God is only in heaven and not near', 'God''s help comes from the sanctuary (immanent, v.2) and from holy heaven (transcendent, v.6) — both his nearness and his exalted majesty are the source of help', 'The sanctuary is in heaven only', 'God''s help comes exclusively through the temple', 'a', 'Help from the sanctuary (v.2) and from his holy heaven (v.6) — Psalm 20 affirms both God''s immanent presence in the earthly sanctuary and his transcendent rule from heaven.'),
('Psalms', 20, 'adults', 8, 'How does Psalm 20 anticipate the theology of the New Testament regarding prayer for leaders?', 'It has no New Testament connection', 'It models intercession for rulers and leaders, anticipating Paul''s instruction to pray for kings and all in authority (1 Timothy 2:1-2)', 'It teaches that kings need no prayer', 'It is only relevant to Israel''s monarchy', 'a', 'Psalm 20''s congregational intercession for the king anticipates Paul''s instruction: "supplications, prayers...be made for all men; for kings, and for all that are in authority" (1 Timothy 2:1-2).');

-- ═══════════════════════════════════════════
-- CHAPTERS 21 – 30
-- ═══════════════════════════════════════════

-- ═══ Psalms Chapter 21 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 21, 'kids', 1, 'What does the king rejoice in according to Psalm 21:1?', 'The strength of the LORD', 'His great army', 'His golden crown', 'His many victories', 'a', 'The king shall joy in thy strength, O LORD; and in thy salvation how greatly shall he rejoice! (Psalm 21:1).'),
('Psalms', 21, 'kids', 2, 'What did God set on the king''s head in Psalm 21:3?', 'A crown of pure gold', 'A wreath of flowers', 'A helmet of iron', 'A turban of white linen', 'a', 'Thou settest a crown of pure gold on his head (Psalm 21:3).'),
('Psalms', 21, 'kids', 3, 'What did the king ask God for and what did God give him?', 'He asked for life, and God gave it to him', 'He asked for wealth, and God gave it to him', 'He asked for victory, and God gave it to him', 'He asked for wisdom, and God gave it to him', 'a', 'He asked life of thee, and thou gavest it him, even length of days for ever and ever (Psalm 21:4).'),
-- Teens
('Psalms', 21, 'teens', 1, 'What blessing did God not withhold from the king in Psalm 21:2?', 'Thou hast not withholden the request of his lips', 'Victory over all his enemies', 'Great wisdom and understanding', 'Long years and many children', 'a', 'Thou hast given him his heart''s desire, and hast not withholden the request of his lips (Psalm 21:2).'),
('Psalms', 21, 'teens', 2, 'What is the king''s glory described as in Psalm 21:5?', 'His glory is great in thy salvation', 'His glory fills the earth', 'His glory surpasses all kings', 'His glory shines like the sun', 'a', 'His glory is great in thy salvation: honour and majesty hast thou laid upon him (Psalm 21:5).'),
('Psalms', 21, 'teens', 3, 'What does God make the king in Psalm 21:6?', 'Most blessed for ever', 'Greatest among all kings', 'A mighty warrior', 'Wise above all others', 'a', 'For thou hast made him most blessed for ever: thou hast made him exceeding glad with thy countenance (Psalm 21:6).'),
('Psalms', 21, 'teens', 4, 'What will happen to the enemies of God''s king according to Psalm 21:9?', 'Thou shalt make them as a fiery oven in the time of thine anger', 'They will scatter and flee', 'They will be imprisoned', 'They will surrender before him', 'a', 'Thou shalt make them as a fiery oven in the time of thine anger (Psalm 21:9).'),
('Psalms', 21, 'teens', 5, 'Why does the king trust in the LORD and not be moved according to Psalm 21:7?', 'Because the king trusteth in the LORD and through the mercy of the most High he shall not be moved', 'Because the king has a great army', 'Because the king has strong walls around his city', 'Because the king is righteous above all others', 'a', 'For the king trusteth in the LORD, and through the mercy of the most High he shall not be moved (Psalm 21:7).'),
-- Adults
('Psalms', 21, 'adults', 1, 'How does Psalm 21 relate to Psalm 20 structurally?', 'They are unrelated psalms', 'Psalm 20 is the pre-battle prayer; Psalm 21 is the post-battle thanksgiving — the two form a royal diptych of intercession and praise', 'Psalm 21 corrects Psalm 20', 'Psalm 20 celebrates victory; Psalm 21 anticipates battle', 'a', 'Psalm 20 is the congregational prayer before battle; Psalm 21 is the thanksgiving after — together they form a liturgical diptych around the king''s warfare.'),
('Psalms', 21, 'adults', 2, 'What does "the mercy of the most High" in Psalm 21:7 emphasize as the basis of the king''s unshakeable stability?', 'The king''s own military strength', 'God''s hesed (covenant lovingkindness) is the ultimate reason the king cannot be moved — not human virtue', 'The king''s righteousness', 'The king''s wisdom in governing', 'a', 'Through the mercy of the most High he shall not be moved (Psalm 21:7) — the king''s stability is rooted in God''s covenant faithfulness, not the king''s own merit.'),
('Psalms', 21, 'adults', 3, 'What does the crown of pure gold in Psalm 21:3 symbolize in the Davidic covenant context?', 'Earthly wealth', 'Divine legitimization and blessing — God himself crowns the king, confirming the Davidic covenant', 'Military conquest', 'The king''s personal righteousness', 'a', 'Thou settest a crown of pure gold on his head (Psalm 21:3) — the golden crown signifies God''s direct authorization of the Davidic king under the covenant.'),
('Psalms', 21, 'adults', 4, 'What does "length of days for ever and ever" in Psalm 21:4 ultimately point to beyond the historical king?', 'A long-lived earthly king', 'The eternal life of the Messianic king — fulfilled in Christ''s resurrection and eternal reign', 'A dynasty of many kings', 'Immortality achieved through obedience', 'a', 'He asked life of thee, and thou gavest it him, even length of days for ever and ever (Psalm 21:4) — pointing to the Messianic king''s eternal life through resurrection.'),
('Psalms', 21, 'adults', 5, 'What does "made him exceeding glad with thy countenance" in Psalm 21:6 reveal about the nature of divine blessing?', 'Wealth makes the king glad', 'The highest joy is not material but relational — the face (countenance) of God is itself the supreme gift', 'Victory in battle is the greatest blessing', 'Wisdom and knowledge are the greatest gifts', 'a', 'Thou hast made him exceeding glad with thy countenance (Psalm 21:6) — the divine face shining on the king is identified as the source of supreme joy.'),
('Psalms', 21, 'adults', 6, 'What does the fiery oven imagery in Psalm 21:9 recall from the Pentateuch?', 'The burning bush', 'The smoke of a furnace from Sodom''s destruction (Genesis 19:28) — divine judgment consuming the enemies', 'The pillar of fire in the wilderness', 'The fire on Mount Sinai', 'a', 'Thou shalt make them as a fiery oven in the time of thine anger (Psalm 21:9) — recalling the smoke of a furnace over Sodom (Genesis 19:28) as divine judgment imagery.'),
('Psalms', 21, 'adults', 7, 'How does the destruction of the king''s enemies''s offspring in Psalm 21:10 function in ancient Near Eastern royal theology?', 'It is excessive cruelty', 'Complete destruction of the enemy lineage ensures no future threat — a standard expression of total divine victory in royal psalms', 'It applies only to specific nations', 'It is a metaphor for spiritual opposition', 'a', 'Their fruit shalt thou destroy from the earth (Psalm 21:10) — complete destruction of enemy offspring reflects ancient Near Eastern total victory language in royal contexts.'),
('Psalms', 21, 'adults', 8, 'How does the congregation''s praise in Psalm 21:13 ("Be thou exalted, LORD") appropriately conclude a royal psalm?', 'It redirects all glory from the king to God', 'It praises the king''s military skill', 'It prays for the king''s next battle', 'It closes with a lament', 'a', 'Be thou exalted, LORD, in thine own strength: so will we sing and praise thy power (Psalm 21:13) — the royal psalm ends by redirecting all honour from the king to God himself.');

-- ═══ Psalms Chapter 22 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 22, 'kids', 1, 'What cry does the suffering person make at the beginning of Psalm 22?', 'My God, my God, why hast thou forsaken me?', 'Save me, O God, for the waters are deep', 'How long wilt thou forget me, O LORD?', 'Out of the depths I cry to thee', 'a', 'My God, my God, why hast thou forsaken me? (Psalm 22:1).'),
('Psalms', 22, 'kids', 2, 'Who spoke the opening words of Psalm 22 on the cross?', 'Jesus', 'The prophet Isaiah', 'King David', 'The angel Gabriel', 'a', 'Jesus cried with a loud voice, saying...My God, my God, why hast thou forsaken me? (Matthew 27:46, quoting Psalm 22:1).'),
('Psalms', 22, 'kids', 3, 'What did the enemies do with the suffering person''s garments in Psalm 22?', 'They cast lots upon my vesture', 'They tore them apart', 'They burned them', 'They hid them', 'a', 'They part my garments among them, and cast lots upon my vesture (Psalm 22:18).'),
-- Teens
('Psalms', 22, 'teens', 1, 'What do the enemies say as they shake their heads and mock the sufferer in Psalm 22?', 'He trusted on the LORD that he would deliver him', 'There is no help for him in God', 'His God has abandoned him forever', 'Let him call on his God if he can', 'a', 'He trusted on the LORD that he would deliver him: let him deliver him, seeing he delighted in him (Psalm 22:8).'),
('Psalms', 22, 'teens', 2, 'What does the sufferer say encircles him in Psalm 22:12-13?', 'Many bulls and a ravening and a roaring lion', 'Armed soldiers and sharp arrows', 'Deep waters and dark pits', 'Walls of fire and walls of ice', 'a', 'Many bulls have compassed me...they gaped upon me with their mouths, as a ravening and a roaring lion (Psalm 22:12-13).'),
('Psalms', 22, 'teens', 3, 'What happens to the body of the sufferer in Psalm 22:14?', 'I am poured out like water and all my bones are out of joint', 'My hands and feet are bound', 'My eyes are covered with darkness', 'My tongue is dried up', 'a', 'I am poured out like water, and all my bones are out of joint: my heart is like wax; it is melted in the midst of my bowels (Psalm 22:14).'),
('Psalms', 22, 'teens', 4, 'What does the sufferer say about his hands and feet in Psalm 22:16?', 'They have pierced my hands and my feet', 'They are bound with chains', 'They are numb with cold', 'They are too weak to move', 'a', 'They pierced my hands and my feet (Psalm 22:16).'),
('Psalms', 22, 'teens', 5, 'What does Psalm 22 say shall be declared to future generations?', 'That he hath done this — his righteousness', 'That God is merciful to the poor', 'That the LORD saves his anointed', 'That Zion shall stand forever', 'a', 'They shall come, and shall declare his righteousness unto a people that shall be born, that he hath done this (Psalm 22:31).'),
-- Adults
('Psalms', 22, 'adults', 1, 'How does Psalm 22 function as a Messianic psalm, given that it was written by David yet fulfilled in Christ?', 'David was describing his own experience only', 'David''s intense personal suffering became a prophetic template fulfilled in Christ''s crucifixion — the details (pierced hands/feet, divided garments, lots, scorning) find precise fulfilment in the Gospel accounts', 'The psalm has no Messianic meaning', 'The Gospels are allegorically interpreting David''s words', 'a', 'Psalm 22 is a typological/prophetic psalm — David''s suffering is real, but the Spirit carried his words beyond his experience to prefigure Christ''s crucifixion with stunning precision.'),
('Psalms', 22, 'adults', 2, 'What is the theological significance of Jesus quoting Psalm 22:1 from the cross in Matthew 27:46?', 'Jesus was expressing despair and lack of faith', 'Jesus was identifying himself as the Psalm 22 sufferer, announcing to those who knew the Psalms that the crucifixion was the fulfilment of this scripture', 'Jesus was quoting scripture from memory without specific intent', 'Jesus was confused about his identity', 'a', 'By quoting Psalm 22:1, Jesus was identifying himself as the prophesied sufferer of Psalm 22, announcing its fulfilment to those who knew the text (Matthew 27:46).'),
('Psalms', 22, 'adults', 3, 'What does "I am a worm, and no man" in Psalm 22:6 convey about the sufferer''s condition?', 'The sufferer has become physically diseased', 'The most extreme humiliation — a worm had no legal standing, could be crushed underfoot, representing utter degradation and contempt', 'The sufferer is confessing sin', 'The sufferer is exaggerating his poverty', 'a', 'I am a worm, and no man; a reproach of men, and despised of the people (Psalm 22:6) — complete human degradation, applied by Paul to Christ''s humiliation (Philippians 2:7-8).'),
('Psalms', 22, 'adults', 4, 'How does John 19:24 connect the dividing of garments and casting of lots to Psalm 22:18?', 'John invented the detail', 'John explicitly states this happened "that the scripture might be fulfilled" quoting Psalm 22:18 — identifying it as direct prophetic fulfilment', 'John is making a loose allusion only', 'The garments detail is only symbolic', 'a', 'John 19:24 — "That the scripture might be fulfilled, which saith, They parted my raiment among them, and for my vesture they did cast lots" — directly fulfils Psalm 22:18.'),
('Psalms', 22, 'adults', 5, 'What is the structural turning point in Psalm 22, and what causes the shift?', 'The psalm ends in despair', 'At verse 24 — "For he hath not despised nor abhorred the affliction of the afflicted" — the mood shifts from abandonment to praise as God''s faithfulness is affirmed', 'The shift happens at verse 1', 'The psalm has no shift — it is entirely lament', 'a', 'The turning point is verse 24 — "he hath not despised nor abhorred the affliction of the afflicted" — from which point the psalm moves into global praise (vv.25-31).'),
('Psalms', 22, 'adults', 6, 'What does "they shall come and shall declare his righteousness unto a people that shall be born" in Psalm 22:31 anticipate?', 'The birth of Israel''s next king', 'The worldwide proclamation of the gospel — the suffering-and-vindication story of the Messianic servant declared to all future generations', 'The writing of the Psalms', 'The rebuilding of Jerusalem after exile', 'a', 'Psalm 22:31 looks forward to future generations declaring "he hath done this" — anticipating the worldwide gospel proclamation of Christ''s death and resurrection.'),
('Psalms', 22, 'adults', 7, 'What does "they shall come and shall declare his righteousness" mean by "his righteousness" in Psalm 22:31?', 'Human moral achievement', 'God''s saving righteousness — his righteous action in vindicating the sufferer through resurrection, the basis of gospel proclamation', 'Israel''s national righteousness', 'The sufferer''s personal righteousness', 'a', '"His righteousness" (Psalm 22:31) — God''s righteousness refers to his saving, vindicating action — his righteous intervention on behalf of the sufferer.'),
('Psalms', 22, 'adults', 8, 'What does the scope of praise in Psalm 22:27-29 ("all the ends of the world...all the kindreds of the nations") reveal about the Messianic suffering?', 'It is limited to Israel only', 'The suffering of the Messianic figure produces universal, worldwide worship — Gentile nations included — previewing the global scope of the gospel', 'It is a hyperbolic expression without specific meaning', 'It refers to David''s empire', 'a', 'All the ends of the world shall remember and turn unto the LORD (Psalm 22:27) — the Messianic suffering produces worldwide worship, fulfilled in the global church.');

-- ═══ Psalms Chapter 23 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 23, 'kids', 1, 'How does Psalm 23 begin?', 'The LORD is my shepherd', 'The LORD is my light', 'The LORD is my strength', 'The LORD is my king', 'a', 'The LORD is my shepherd; I shall not want (Psalm 23:1).'),
('Psalms', 23, 'kids', 2, 'Where does the shepherd lead the sheep to rest?', 'Green pastures and still waters', 'High mountains and deep rivers', 'Cool caves and running streams', 'Soft meadows and tall trees', 'a', 'He maketh me to lie down in green pastures: he leadeth me beside the still waters (Psalm 23:2).'),
('Psalms', 23, 'kids', 3, 'What overflows in Psalm 23?', 'My cup runneth over', 'My heart with joy', 'My hands with blessings', 'My house with people', 'a', 'Thou preparest a table before me in the presence of mine enemies: thou anointest my head with oil; my cup runneth over (Psalm 23:5).'),
-- Teens
('Psalms', 23, 'teens', 1, 'What valley does the psalmist walk through without fear?', 'The valley of the shadow of death', 'The valley of dry bones', 'The valley of weeping', 'The valley of darkness', 'a', 'Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me (Psalm 23:4).'),
('Psalms', 23, 'teens', 2, 'What two items does the shepherd carry in Psalm 23:4?', 'Thy rod and thy staff', 'Thy sword and thy shield', 'Thy lamp and thy staff', 'Thy bow and thy quiver', 'a', 'Thy rod and thy staff they comfort me (Psalm 23:4).'),
('Psalms', 23, 'teens', 3, 'Where does God prepare a table for the psalmist?', 'In the presence of mine enemies', 'In the house of the LORD', 'In the green pastures', 'In the valley', 'a', 'Thou preparest a table before me in the presence of mine enemies (Psalm 23:5).'),
('Psalms', 23, 'teens', 4, 'What does the shepherd do to the sheep''s soul in Psalm 23:3?', 'He restoreth my soul', 'He feeds my soul', 'He cleanses my soul', 'He guards my soul', 'a', 'He restoreth my soul: he leadeth me in the paths of righteousness for his name''s sake (Psalm 23:3).'),
('Psalms', 23, 'teens', 5, 'What will follow the psalmist all the days of his life?', 'Goodness and mercy', 'Joy and peace', 'Strength and honour', 'Wisdom and understanding', 'a', 'Surely goodness and mercy shall follow me all the days of my life (Psalm 23:6).'),
-- Adults
('Psalms', 23, 'adults', 1, 'What is the dual metaphor of Psalm 23, and at what point does the metaphor shift?', 'It is entirely a shepherd metaphor', 'Verses 1-4 use the shepherd/sheep metaphor; verses 5-6 shift to the host/guest metaphor — God as a generous host preparing a banquet', 'It is entirely a banquet metaphor', 'Verses 1-3 describe creation; verses 4-6 describe judgment', 'a', 'Psalm 23 uses two metaphors: the shepherd and his sheep (vv.1-4) and the gracious host and honoured guest (vv.5-6), both expressing God''s comprehensive provision and care.'),
('Psalms', 23, 'adults', 2, 'What is the significance of "for his name''s sake" in Psalm 23:3?', 'David is claiming the LORD''s name as a charm', 'God''s guidance of the righteous paths is grounded in his own covenant character and reputation — not David''s merit', 'God acts for his own glory in a self-serving way', 'The name is a title of power only', 'a', 'He leadeth me in the paths of righteousness for his name''s sake (Psalm 23:3) — God''s guidance is motivated by his own character and covenant faithfulness.'),
('Psalms', 23, 'adults', 3, 'What does "the valley of the shadow of death" (tsalmaveth) convey in Hebrew?', 'A physical location near Jerusalem', 'Deep darkness or the shadow of death — expressing the most dangerous and terrifying situations of life', 'A valley used for burial', 'A metaphor for spiritual darkness only', 'a', 'Tsalmaveth (Psalm 23:4) combines darkness and death — the deepest, most life-threatening darkness, not merely hardship but mortal danger.'),
('Psalms', 23, 'adults', 4, 'What is the significance of anointing the head with oil in Psalm 23:5 in the ancient Near Eastern context?', 'It symbolizes baptism', 'It was the mark of an honoured guest — oil was poured on a guest''s head as a sign of special welcome and dignity', 'It was a priestly rite', 'It symbolizes healing from sickness', 'a', 'Thou anointest my head with oil (Psalm 23:5) — in ancient Near Eastern hospitality, anointing a guest''s head with oil was a mark of highest honour and welcome.'),
('Psalms', 23, 'adults', 5, 'What does "goodness and mercy shall follow me" convey differently from saying "goodness and mercy shall be with me"?', 'No difference — they mean the same', 'To "follow" (radaph — to pursue) suggests goodness and mercy actively chase the psalmist — they are not passive companions but aggressive pursuers', 'Following implies they come after problems', 'Following is a weaker form of accompaniment', 'a', 'Surely goodness and mercy shall follow me (Psalm 23:6) — the Hebrew radaph means to pursue or chase, suggesting God''s goodness actively pursues the psalmist.'),
('Psalms', 23, 'adults', 6, 'How does Jesus'' declaration "I am the good shepherd" in John 10:11 relate to Psalm 23?', 'It is a coincidental metaphor', 'Jesus directly applies the divine shepherd role of Psalm 23 to himself, claiming to be the fulfillment of YHWH the shepherd', 'Jesus was quoting Ezekiel 34 only', 'Jesus was describing an ideal human leader', 'a', '"I am the good shepherd" (John 10:11) — Jesus identifies himself as the YHWH-shepherd of Psalm 23, claiming divine identity and fulfilling the Messianic shepherd prophecies.'),
('Psalms', 23, 'adults', 7, 'What does preparing a table "in the presence of mine enemies" in Psalm 23:5 demonstrate about God''s protection?', 'The enemies are irrelevant to God', 'God''s provision is so complete and his protection so total that the psalmist can feast with enemies nearby — a declaration of unshakeable security', 'The enemies are invited to share the meal', 'The table is in a safe place hidden from enemies', 'a', 'God prepares a banquet in plain view of enemies (Psalm 23:5) — demonstrating that God''s protection is absolute and the enemies'' presence cannot diminish or threaten his provision.'),
('Psalms', 23, 'adults', 8, 'What does "I will dwell in the house of the LORD for ever" in Psalm 23:6 express as the psalm''s ultimate aspiration?', 'Permanent temple residence as a priest', 'Eternal fellowship with God — the ultimate destination of the shepherd''s leading and the host''s welcoming', 'Continued earthly life in Jerusalem', 'A promise of reincarnation', 'a', 'I will dwell in the house of the LORD for ever (Psalm 23:6) — the psalm''s goal is not mere safety but eternal communion with God, the greatest good of all.');

-- ═══ Psalms Chapter 24 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 24, 'kids', 1, 'Who does Psalm 24 say the earth belongs to?', 'The LORD', 'The king of Israel', 'The angels', 'The people of God', 'a', 'The earth is the LORD''s, and the fulness thereof; the world, and they that dwell therein (Psalm 24:1).'),
('Psalms', 24, 'kids', 2, 'What are the gates told to do in Psalm 24?', 'Lift up your heads', 'Open wide', 'Stand firm', 'Bow down low', 'a', 'Lift up your heads, O ye gates; and be ye lift up, ye everlasting doors; and the King of glory shall come in (Psalm 24:7).'),
('Psalms', 24, 'kids', 3, 'What is the King called in Psalm 24?', 'The King of glory', 'The King of Israel', 'The King of heaven', 'The King eternal', 'a', 'Who is this King of glory? The LORD strong and mighty, the LORD mighty in battle (Psalm 24:8).'),
-- Teens
('Psalms', 24, 'teens', 1, 'How did God found the earth according to Psalm 24:2?', 'Upon the seas and floods', 'Upon the mountains', 'Upon the deep waters', 'Upon the rock', 'a', 'For he hath founded it upon the seas, and established it upon the floods (Psalm 24:2).'),
('Psalms', 24, 'teens', 2, 'Who shall ascend into the hill of the LORD according to Psalm 24:4?', 'He that hath clean hands and a pure heart', 'He that hath offered the greatest sacrifice', 'He that hath served in the temple', 'He that hath kept all the feasts', 'a', 'He that hath clean hands, and a pure heart; who hath not lifted up his soul unto vanity, nor sworn deceitfully (Psalm 24:4).'),
('Psalms', 24, 'teens', 3, 'What will the person with clean hands and a pure heart receive?', 'Blessing from the LORD and righteousness from the God of his salvation', 'Victory over his enemies', 'Long life and many children', 'Wisdom and understanding', 'a', 'He shall receive the blessing from the LORD, and righteousness from the God of his salvation (Psalm 24:5).'),
('Psalms', 24, 'teens', 4, 'Who is the King of glory described as in Psalm 24:8?', 'The LORD strong and mighty, the LORD mighty in battle', 'The LORD of all the earth', 'The LORD who sits above the cherubim', 'The LORD who made the heavens', 'a', 'Who is this King of glory? The LORD strong and mighty, the LORD mighty in battle (Psalm 24:8).'),
('Psalms', 24, 'teens', 5, 'What is said about those who seek God''s face in Psalm 24:6?', 'This is the generation of them that seek him', 'They shall be blessed above all', 'They shall dwell on God''s holy hill', 'They shall receive a great reward', 'a', 'This is the generation of them that seek him, that seek thy face, O Jacob (Psalm 24:6).'),
-- Adults
('Psalms', 24, 'adults', 1, 'What is the proposed liturgical context of Psalm 24 in Jewish tradition?', 'A psalm for private prayer', 'A processional psalm for the ark being brought to Jerusalem (2 Samuel 6) or a Sabbath morning liturgy', 'A psalm for the Day of Atonement', 'A psalm for the Feast of Tabernacles', 'a', 'Psalm 24 is traditionally associated with the bringing of the ark to Jerusalem (2 Samuel 6) and is the Sabbath morning psalm in Jewish liturgy.'),
('Psalms', 24, 'adults', 2, 'What is the cosmological claim of "he hath founded it upon the seas" in Psalm 24:2, and how does it subvert ancient Near Eastern mythology?', 'Israel believed the sea was the source of all life', 'In ancient Near Eastern myths, the sea was a primordial force opposed to the creator gods — Psalm 24 asserts that God simply founded the earth on the seas, completely ruling them', 'It describes how God created the oceans', 'It proves the earth is flat', 'a', 'He hath founded it upon the seas (Psalm 24:2) — while ancient Near Eastern gods fought the sea, Israel''s God simply uses the seas as a foundation, asserting absolute sovereignty.'),
('Psalms', 24, 'adults', 3, 'What does "clean hands and a pure heart" in Psalm 24:4 represent as a complete description of moral integrity?', 'Two separate requirements', 'Outward action (clean hands) and inner motive (pure heart) — the full integration of external conduct and internal character', 'Only ritual washings', 'Only inner spiritual states', 'a', 'Clean hands (external action) and pure heart (internal motive) in Psalm 24:4 — the complete picture of integrity: doing right for right reasons.'),
('Psalms', 24, 'adults', 4, 'How is the question-and-answer liturgy "Who is this King of glory?" in Psalm 24:8-10 thought to have functioned?', 'It was a riddle', 'A processional liturgy where the question was called from inside the gates and answered by the approaching procession bearing the ark', 'A song for the temple choir only', 'A private meditation of David', 'a', 'The antiphonal call-and-response in Psalm 24:7-10 was likely a processional liturgy — voices inside the gates asking, the procession outside answering — as the ark entered the city.'),
('Psalms', 24, 'adults', 5, 'What does the repeated "lift up your heads, O ye gates" (Psalm 24:7, 9) accomplish liturgically and theologically?', 'It describes physical gates opening', 'The repetition creates an intensifying dramatic effect — the King of glory demands and deserves the fullest possible welcome from all creation', 'It was sung twice because the first attempt was insufficient', 'It is a poetic device without theological meaning', 'a', 'The repetition of "lift up your heads" (Psalm 24:7, 9) creates a crescendo, intensifying the drama of the divine King''s entry and demanding the universe''s fullest welcome.'),
('Psalms', 24, 'adults', 6, 'How is Psalm 24 applied in Christian worship, particularly in relation to Ascension and Advent?', 'It has no Christian application', 'It is applied to Christ''s ascension — the King of glory entering heaven''s gates — and to his second coming; early church read it in this Messianic framework', 'It applies only to the temple liturgy', 'It applies only to the Davidic monarchy', 'a', 'Psalm 24 is applied in Christian tradition to Christ''s ascension (the King of glory ascending to heaven) and his second coming, citing patristic and early Christian interpretation.'),
('Psalms', 24, 'adults', 7, 'What does "the LORD of hosts" as the title for the King of glory in Psalm 24:10 convey?', 'God is a military general', 'God commands the heavenly armies — the divine warrior title expressing his supreme authority over all spiritual and physical powers', 'God created many angels', 'God rules the nations through earthly kings', 'a', 'The LORD of hosts, he is the King of glory (Psalm 24:10) — LORD of hosts (YHWH Sabaoth) is the divine warrior title, expressing God''s supreme command over all heavenly powers.'),
('Psalms', 24, 'adults', 8, 'How does "the fulness thereof" in Psalm 24:1 set the theological foundation for all that follows about who may ascend God''s hill?', 'It is a poetic filler phrase', 'If everything belongs to God — the earth, its contents, and all inhabitants — then God has the absolute right to define the conditions of approach and worship', 'It means the earth is too full of people', 'It is an agricultural reference to harvest', 'a', 'The earth is the LORD''s, and the fulness thereof (Psalm 24:1) — because God owns everything, he has absolute authority to set the moral conditions for approaching him.');

-- ═══ Psalms Chapter 25 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 25, 'kids', 1, 'What does David ask God to show him in Psalm 25?', 'Shew me thy ways, O LORD', 'Shew me thy power', 'Shew me thy glory', 'Shew me thy temple', 'a', 'Shew me thy ways, O LORD; teach me thy paths (Psalm 25:4).'),
('Psalms', 25, 'kids', 2, 'What does David ask God NOT to remember?', 'The sins of my youth', 'My mistakes in battle', 'My foolish words', 'My disobedience to parents', 'a', 'Remember not the sins of my youth, nor my transgressions: according to thy mercy remember thou me (Psalm 25:7).'),
('Psalms', 25, 'kids', 3, 'What does David lift up to God in Psalm 25?', 'My soul', 'My hands', 'My voice', 'My eyes', 'a', 'Unto thee, O LORD, do I lift up my soul (Psalm 25:1).'),
-- Teens
('Psalms', 25, 'teens', 1, 'What does David say about waiting on the LORD in Psalm 25?', 'On thee do I wait all the day', 'I will wait until the morning', 'I wait with great patience for thee', 'I wait in the temple for thy answer', 'a', 'Lead me in thy truth, and teach me: for thou art the God of my salvation; on thee do I wait all the day (Psalm 25:5).'),
('Psalms', 25, 'teens', 2, 'Who does God guide in judgment and teach his way according to Psalm 25:9?', 'The meek', 'The priests and Levites', 'The prophets', 'The righteous rulers', 'a', 'The meek will he guide in judgment: and the meek will he teach his way (Psalm 25:9).'),
('Psalms', 25, 'teens', 3, 'What is the secret of the LORD and who is it with in Psalm 25:14?', 'The secret of the LORD is with them that fear him', 'The secret of the LORD is hidden in the law', 'The secret of the LORD is in the temple', 'The secret of the LORD is revealed to prophets', 'a', 'The secret of the LORD is with them that fear him; and he will shew them his covenant (Psalm 25:14).'),
('Psalms', 25, 'teens', 4, 'What does David ask God to look upon in Psalm 25:18?', 'Mine affliction and my pain; and forgive all my sins', 'My suffering and my tears', 'My enemies and my distress', 'My weakness and my need', 'a', 'Look upon mine affliction and my pain; and forgive all my sins (Psalm 25:18).'),
('Psalms', 25, 'teens', 5, 'What does David say his eyes are ever toward in Psalm 25?', 'The LORD', 'The heavens', 'The temple', 'The holy mountain', 'a', 'Mine eyes are ever toward the LORD; for he shall pluck my feet out of the net (Psalm 25:15).'),
-- Adults
('Psalms', 25, 'adults', 1, 'What literary structure does Psalm 25 employ in the original Hebrew?', 'A chiasm', 'An alphabetic acrostic — each verse begins with successive letters of the Hebrew alphabet', 'A triplet refrain structure', 'A question-and-answer dialogue', 'a', 'Psalm 25 is an alphabetic acrostic in Hebrew — each verse beginning with successive letters from Aleph to Taw, demonstrating both artistry and completeness.'),
('Psalms', 25, 'adults', 2, 'What does the "secret of the LORD" (sod YHWH) in Psalm 25:14 refer to?', 'Hidden mystical knowledge reserved for prophets', 'Intimate covenantal friendship — the counsel and communion God shares with those who fear him', 'Secret codes in the law', 'Hidden knowledge of the future', 'a', 'The secret of the LORD is with them that fear him (Psalm 25:14) — sod (secret/council) refers to intimate friendship and covenantal communion, as in Job 29:4 and Proverbs 3:32.'),
('Psalms', 25, 'adults', 3, 'What does David''s prayer "remember not the sins of my youth" in Psalm 25:7 reveal about the relationship between God''s memory and forgiveness?', 'God literally forgets sins', 'God''s "not remembering" is a covenantal act — choosing not to hold sins against the pardoned person, based on his mercy', 'Youth sins are less serious', 'God only forgives sins of adulthood', 'a', 'Remember not the sins of my youth (Psalm 25:7) — God''s "not remembering" is a covenantal act of forgiveness, not literal amnesia, grounded in his mercy.'),
('Psalms', 25, 'adults', 4, 'What does David''s repeated emphasis on "teach me," "lead me," and "guide me" in Psalm 25 reveal about the nature of the life of faith?', 'It shows David was ignorant', 'Living faithfully requires continuous divine instruction and guidance — it is not self-directed but God-directed', 'It shows David was too dependent on others', 'It shows that God''s ways must be learned only once', 'a', 'The repeated petitions to be taught and guided (Psalm 25:4-5, 8-9) show that the life of faith is not self-sufficient but requires constant dependence on God''s instruction.'),
('Psalms', 25, 'adults', 5, 'What is the relationship between fearing God and receiving his covenant instruction in Psalm 25:12-14?', 'The fearful receive punishment', 'Those who fear God receive his guidance, inherit the land, and are shown his covenant — fear of God is the gateway to divine intimacy', 'Only priests who fear God receive instruction', 'Fearing God brings material reward only', 'a', 'What man is he that feareth the LORD? him shall he teach...his soul shall dwell at ease...the secret of the LORD is with them that fear him (Psalm 25:12-14).'),
('Psalms', 25, 'adults', 6, 'What does "the paths of the LORD are mercy and truth" in Psalm 25:10 assert about God''s way of dealing with mankind?', 'God''s paths are difficult and hard to find', 'Every path God leads his people along is characterized by hesed (covenant love) and emet (faithfulness) — the twin pillars of his character', 'God demands truth from people before he shows mercy', 'God''s mercy is for some paths and his truth for others', 'a', 'All the paths of the LORD are mercy and truth (Psalm 25:10) — hesed and emet (steadfast love and faithfulness) characterize every divine dealing with his people.'),
('Psalms', 25, 'adults', 7, 'What does David''s closing prayer "Redeem Israel, O God, out of all his troubles" in Psalm 25:22 do to the personal psalm?', 'It is an unrelated addition', 'It broadens the personal lament into a corporate intercession, connecting individual suffering to the national covenant community', 'It shows David was thinking of politics only', 'It shows the psalm was written by two different authors', 'a', '"Redeem Israel, O God, out of all his troubles" (Psalm 25:22) — the personal psalm ends in corporate intercession, connecting the individual''s suffering to the whole covenant people.'),
('Psalms', 25, 'adults', 8, 'How does the instruction theme of Psalm 25 connect to the wisdom literature tradition of Israel?', 'Psalm 25 has no connection to wisdom literature', 'Psalm 25 shares the wisdom tradition''s emphasis on fearing God as the beginning of wisdom and seeking instruction in the way of life — connecting prayer and sapiential instruction', 'Psalm 25 contradicts wisdom literature', 'Only Proverbs contains wisdom themes', 'a', 'Psalm 25 connects to wisdom literature: fear of God (v.14), divine instruction in "the way" (vv.4-5, 8-9), and the meek receiving guidance — all central wisdom themes.');

-- ═══ Psalms Chapter 26 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 26, 'kids', 1, 'What does David ask God to do to him in Psalm 26?', 'Judge me, O LORD', 'Forgive me, O LORD', 'Guide me, O LORD', 'Teach me, O LORD', 'a', 'Judge me, O LORD; for I have walked in mine integrity (Psalm 26:1).'),
('Psalms', 26, 'kids', 2, 'What does David love in Psalm 26?', 'The habitation of thy house and the place where thine honour dwelleth', 'The mountains and rivers God made', 'The songs of the temple singers', 'The company of God''s people', 'a', 'LORD, I have loved the habitation of thy house, and the place where thine honour dwelleth (Psalm 26:8).'),
('Psalms', 26, 'kids', 3, 'What does David do around the altar in Psalm 26?', 'I will compass thine altar', 'I will sing praises to thee', 'I will offer sacrifices to thee', 'I will bring my gifts to thee', 'a', 'That I may publish with the voice of thanksgiving, and tell of all thy wondrous works. LORD, I have loved the habitation of thy house...I will compass thine altar, O LORD (Psalm 26:7-8, 6).'),
-- Teens
('Psalms', 26, 'teens', 1, 'What does David ask God to examine in Psalm 26:2?', 'Examine me, O LORD, and prove me; try my reins and my heart', 'Examine my words and my deeds', 'Examine my enemies and judge them', 'Examine my offerings and accept them', 'a', 'Examine me, O LORD, and prove me; try my reins and my heart (Psalm 26:2).'),
('Psalms', 26, 'teens', 2, 'With what kind of men does David say he has NOT sat in Psalm 26:4?', 'Vain persons, dissemblers', 'Liars and murderers', 'The proud and the violent', 'The foolish and the ignorant', 'a', 'I have not sat with vain persons, neither will I go in with dissemblers (Psalm 26:4).'),
('Psalms', 26, 'teens', 3, 'What congregation does David hate in Psalm 26:5?', 'The congregation of evil doers', 'The congregation of the heathen', 'The congregation of the violent', 'The congregation of the scornful', 'a', 'I have hated the congregation of evil doers; and will not sit with the wicked (Psalm 26:5).'),
('Psalms', 26, 'teens', 4, 'What does David wash in Psalm 26:6?', 'Mine hands in innocency', 'My feet in the river', 'My face in the morning', 'My garments in the fountain', 'a', 'I will wash mine hands in innocency: so will I compass thine altar, O LORD (Psalm 26:6).'),
('Psalms', 26, 'teens', 5, 'What does David ask God not to do to him in Psalm 26:9?', 'Gather not my soul with sinners', 'Take not my life with the wicked', 'Send not my soul into darkness', 'Cast not me away from thy presence', 'a', 'Gather not my soul with sinners, nor my life with bloody men (Psalm 26:9).'),
-- Adults
('Psalms', 26, 'adults', 1, 'What type of psalm is Psalm 26, and what is unusual about its opening verse?', 'A lament with a prayer for help', 'A psalm of personal integrity — unusually opening with an appeal to God to judge the psalmist rather than to forgive, based on claimed innocence', 'A thanksgiving psalm', 'A royal psalm', 'a', 'Judge me, O LORD; for I have walked in mine integrity (Psalm 26:1) — unusual in that David invites divine judgment based on integrity, not seeking pardon but vindication.'),
('Psalms', 26, 'adults', 2, 'What does the judicial language of "judge me" in Psalm 26:1 suggest about the background of this psalm?', 'David is confessing general sinfulness', 'David is under false accusation and is appealing to God as the supreme court to vindicate his integrity against unjust charges', 'David is asking God to punish him appropriately', 'David is making a philosophical inquiry', 'a', 'Judge me, O LORD (Psalm 26:1) — the judicial language suggests a specific false accusation context; David is appealing to the divine court for vindication.'),
('Psalms', 26, 'adults', 3, 'What does "try my reins and my heart" in Psalm 26:2 mean, and what is the relationship between these two?', 'A medical examination of kidneys and heart', 'The reins (kidneys) represent the seat of deep motives and emotions; the heart represents the will and intellect — God is asked to examine the total inner person', 'The reins represent actions and the heart represents speech', 'They are synonyms with no distinction', 'a', 'Examine me...try my reins and my heart (Psalm 26:2) — the reins (deepest emotions/motives) and heart (will/intellect) together represent the complete inner person laid open before God.'),
('Psalms', 26, 'adults', 4, 'What does David''s washing of hands in innocency in Psalm 26:6 draw on culturally and theologically?', 'A morning hygiene ritual', 'The ancient ritual of washing hands to symbolize innocence of a specific charge — as in the declaration of innocence in Deuteronomy 21:6-7', 'A temple purification requirement', 'A metaphor for repentance only', 'a', 'I will wash mine hands in innocency (Psalm 26:6) — echoes the judicial hand-washing of innocence in Deuteronomy 21:6-7, declaring freedom from a specific charge.'),
('Psalms', 26, 'adults', 5, 'What is the theological significance of David''s "I have loved the habitation of thy house" in Psalm 26:8?', 'David preferred architecture', 'Love for God''s dwelling place expresses the heart''s deepest longing for God''s presence — the sanctuary is where God''s glory and honour dwell', 'David was a temple architect', 'David preferred the temple to the palace', 'a', 'LORD, I have loved the habitation of thy house, and the place where thine honour dwelleth (Psalm 26:8) — love for God''s house is love for God''s presence.'),
('Psalms', 26, 'adults', 6, 'How does the closing promise "I will walk in mine integrity" in Psalm 26:11 relate to the opening claim of the same in Psalm 26:1?', 'They contradict each other', 'The opening claim (v.1) is historical fact; the closing promise (v.11) is renewed commitment — together showing integrity as both past reality and future intention', 'The closing is a correction of the opening', 'Both statements are aspirational only', 'a', 'Opening: "I have walked in mine integrity" (Psalm 26:1); closing: "I will walk in mine integrity" (Psalm 26:11) — past integrity and future commitment form an inclusio around the psalm.'),
('Psalms', 26, 'adults', 7, 'What does "tell of all thy wondrous works" in Psalm 26:7 reveal about the purpose of approaching God''s altar?', 'The altar is for silent prayer', 'The approach to God''s presence is for proclamation — the experience of God''s grace produces testimony and the public declaration of his mighty acts', 'The altar is only for sacrifice', 'Proclamation replaces sacrifice in the new covenant', 'a', 'That I may publish with the voice of thanksgiving, and tell of all thy wondrous works (Psalm 26:7) — approaching the altar leads to proclamation of God''s marvelous deeds.'),
('Psalms', 26, 'adults', 8, 'How does Psalm 26''s model of integrity-based prayer challenge a purely grace-based understanding of prayer?', 'It shows that merit earns God''s favour', 'It demonstrates that integrity and grace coexist — David appeals to grace ("redeem me and be merciful" v.11) even while claiming integrity; the two are not contradictory', 'It proves the law saves', 'It contradicts the New Testament''s emphasis on grace', 'a', 'Psalm 26 holds together integrity (vv.1-3, 11) and grace (v.11 "be merciful unto me") — showing that honest integrity-claims and trust in God''s mercy are not contradictory in biblical faith.');

-- ═══ Psalms Chapter 27 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 27, 'kids', 1, 'How does Psalm 27 begin?', 'The LORD is my light and my salvation', 'The LORD is my shepherd', 'The LORD is my rock and my fortress', 'The LORD is my strength and my song', 'a', 'The LORD is my light and my salvation; whom shall I fear? (Psalm 27:1).'),
('Psalms', 27, 'kids', 2, 'What one thing does David desire more than anything else?', 'To dwell in the house of the LORD', 'To have great riches', 'To win every battle', 'To live a long life', 'a', 'One thing have I desired of the LORD, that will I seek after; that I may dwell in the house of the LORD all the days of my life (Psalm 27:4).'),
('Psalms', 27, 'kids', 3, 'What does David tell us to do at the end of Psalm 27?', 'Wait on the LORD', 'Trust in God''s strength', 'Sing praise to God', 'Pray without ceasing', 'a', 'Wait on the LORD: be of good courage, and he shall strengthen thine heart: wait, I say, on the LORD (Psalm 27:14).'),
-- Teens
('Psalms', 27, 'teens', 1, 'What does David say he will not fear even if an army encamp against him in Psalm 27?', 'My heart shall not fear', 'I will trust in the LORD only', 'I will fight without fear', 'I will pray without ceasing', 'a', 'Though an host should encamp against me, my heart shall not fear (Psalm 27:3).'),
('Psalms', 27, 'teens', 2, 'What does David say God will do for him in the time of trouble according to Psalm 27:5?', 'He shall hide me in his pavilion: in the secret of his tabernacle shall he hide me', 'He shall send his angel to protect me', 'He shall scatter my enemies before me', 'He shall give me a safe city', 'a', 'In the time of trouble he shall hide me in his pavilion: in the secret of his tabernacle shall he hide me (Psalm 27:5).'),
('Psalms', 27, 'teens', 3, 'What does David seek — God''s face — and what was he told?', 'Seek ye my face; and my heart said, Thy face, LORD, will I seek', 'Seek God in the sanctuary always', 'Seek the LORD while he may be found', 'Seek God in prayer each morning', 'a', 'When thou saidst, Seek ye my face; my heart said unto thee, Thy face, LORD, will I seek (Psalm 27:8).'),
('Psalms', 27, 'teens', 4, 'What does David say his father and mother might do but what would God do instead?', 'When my father and my mother forsake me, then the LORD will take me up', 'My parents grow old but God grows not', 'My parents sleep but God never sleeps', 'My parents err but God never errs', 'a', 'When my father and my mother forsake me, then the LORD will take me up (Psalm 27:10).'),
('Psalms', 27, 'teens', 5, 'What does David ask to behold in the house of the LORD in Psalm 27:4?', 'The beauty of the LORD', 'The ark of the covenant', 'The glory of the cherubim', 'The golden lampstand', 'a', 'To behold the beauty of the LORD, and to enquire in his temple (Psalm 27:4).'),
-- Adults
('Psalms', 27, 'adults', 1, 'What is the widely discussed structural debate about Psalm 27?', 'Whether it was written by David or another psalmist', 'Whether Psalm 27 is one psalm or two — vv.1-6 expressing confident trust and vv.7-14 expressing anxious lament — reflecting either one poet''s experience or two separate compositions', 'Whether it belongs in Book 1 or Book 2', 'Whether it is Messianic or purely personal', 'a', 'Scholars debate whether Psalm 27 is a unified psalm (trust flowing into crisis) or two compositions — the confident opening (1-6) and the anxious lament (7-14) — differing in tone.'),
('Psalms', 27, 'adults', 2, 'What is the theological weight of the opening declaration "The LORD is my light and my salvation" in Psalm 27:1?', 'A general statement about God''s attributes', 'It combines two critical divine roles: light (guidance in darkness) and salvation (deliverance from danger) — making God the total answer to fear', 'A liturgical greeting', 'A metaphor for the sunrise', 'a', 'The LORD is my light (guidance in darkness) and my salvation (deliverance from danger) (Psalm 27:1) — these two attributes together make fear impossible for the believer.'),
('Psalms', 27, 'adults', 3, 'What is the "one thing" David desires in Psalm 27:4, and why is the singularity of focus significant?', 'David wanted only the temple built', 'Singular focus on dwelling in God''s presence above all other goods — expressing total devotion to communion with God as the supreme life-ambition', 'David wanted to be king forever', 'David wanted victory over all enemies', 'a', 'One thing have I desired...that I may dwell in the house of the LORD all the days of my life (Psalm 27:4) — singular focus on God''s presence as life''s supreme and only essential desire.'),
('Psalms', 27, 'adults', 4, 'What does "behold the beauty of the LORD" in Psalm 27:4 express about the nature of worship?', 'Temple architecture is the object of admiration', 'The goal of worship is the contemplation of God''s own loveliness and character — noam (beauty/pleasantness) suggests God himself is the supreme delight', 'Beauty refers to the ritual ceremonies', 'David was an artist who appreciated aesthetics', 'a', 'To behold the beauty (noam — pleasantness/loveliness) of the LORD (Psalm 27:4) — the goal of approaching God is not petitioning but gazing on his character with delight.'),
('Psalms', 27, 'adults', 5, 'What does "he shall hide me in his pavilion" in Psalm 27:5 evoke regarding divine protection?', 'A specific room in the temple', 'The sukkah (booth/pavilion) — evoking the Feast of Tabernacles, God''s sheltering presence with his people in the wilderness', 'A metaphor for sleep', 'A military shelter', 'a', 'In the time of trouble he shall hide me in his pavilion (sukkah) (Psalm 27:5) — the word evokes the feast of Tabernacles and God''s wilderness-sheltering presence.'),
('Psalms', 27, 'adults', 6, 'What is the significance of David''s claim that even his father and mother might forsake him, but the LORD would take him up in Psalm 27:10?', 'David had troubled family relationships', 'It establishes God as a more reliable attachment figure than even the most fundamental human relationships — a radical declaration of divine faithfulness', 'It predicts that David''s parents would die soon', 'It is a hypothetical with no real meaning', 'a', 'When my father and my mother forsake me, then the LORD will take me up (Psalm 27:10) — setting God''s faithfulness above even the most reliable human bond.'),
('Psalms', 27, 'adults', 7, 'What does "to enquire in his temple" in Psalm 27:4 suggest about the relationship between worship and seeking divine guidance?', 'Enquiry is done separately from worship', 'The temple is both the place of adoration (beholding beauty) and enquiry (seeking God''s will) — worship and discernment are inseparable activities', 'Only priests could enquire in the temple', 'Enquiry replaces praise in times of crisis', 'a', 'To behold the beauty of the LORD, and to enquire in his temple (Psalm 27:4) — adoration and seeking God''s direction are simultaneous activities of the worshipper.'),
('Psalms', 27, 'adults', 8, 'How does the doubled "Wait on the LORD" in Psalm 27:14 function as the psalm''s conclusion?', 'It is a liturgical formula added by an editor', 'The repetition is a rhetorical intensification — waiting on God is not passive resignation but courageous, active trust that strengthens the heart', 'It shows David lost confidence', 'It is addressed to future readers only', 'a', 'Wait on the LORD: be of good courage, and he shall strengthen thine heart: wait, I say, on the LORD (Psalm 27:14) — the doubled imperative is emphatic, urging active, courageous expectation.');

-- ═══ Psalms Chapter 28 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 28, 'kids', 1, 'What does David call God in his cry at the start of Psalm 28?', 'O LORD my rock', 'O LORD my shield', 'O LORD my shepherd', 'O LORD my fortress', 'a', 'Unto thee will I cry, O LORD my rock; be not silent to me (Psalm 28:1).'),
('Psalms', 28, 'kids', 2, 'What does David say the LORD is and who does he trust in Psalm 28?', 'My strength and my shield; my heart trusted in him', 'My rock and my fortress; I trust in him always', 'My shepherd and my guide; I follow him always', 'My light and my salvation; I shall not fear', 'a', 'The LORD is my strength and my shield; my heart trusted in him, and I am helped (Psalm 28:7).'),
('Psalms', 28, 'kids', 3, 'What does David say the LORD is to his anointed in Psalm 28?', 'The saving strength of his anointed', 'The crown upon his head', 'The helper of his king', 'The defender of his people', 'a', 'Save thy people, and bless thine inheritance: feed them also, and lift them up for ever. The LORD is their strength, and he is the saving strength of his anointed (Psalm 28:8-9).'),
-- Teens
('Psalms', 28, 'teens', 1, 'What does David fear will happen if God is silent to him in Psalm 28?', 'I become like them that go down into the pit', 'My enemies will overcome me', 'I will lose all hope', 'My prayers will go unanswered forever', 'a', 'Be not silent to me: lest, if thou be silent to me, I become like them that go down into the pit (Psalm 28:1).'),
('Psalms', 28, 'teens', 2, 'Toward what does David lift his hands in Psalm 28?', 'Toward thy holy oracle', 'Toward the heavens above', 'Toward the temple gates', 'Toward the holy mountain', 'a', 'Hear the voice of my supplications, when I cry unto thee, when I lift up my hands toward thy holy oracle (Psalm 28:2).'),
('Psalms', 28, 'teens', 3, 'What do the wicked do in Psalm 28:3 that makes them dangerous?', 'They speak peace to their neighbours but mischief is in their hearts', 'They set traps for the innocent', 'They slander God''s name publicly', 'They oppress the poor with violence', 'a', 'Which speak peace to their neighbours, but mischief is in their hearts (Psalm 28:3).'),
('Psalms', 28, 'teens', 4, 'What does David ask God to give the wicked according to their deeds in Psalm 28:4?', 'Give them according to their deeds and according to the wickedness of their endeavours', 'Destroy them with fire from heaven', 'Scatter them to the four winds', 'Remove them from the land', 'a', 'Give them according to their deeds, and according to the wickedness of their endeavours (Psalm 28:4).'),
('Psalms', 28, 'teens', 5, 'What does David''s heart do and what does his song break into in Psalm 28:7?', 'My heart trusted in him and I am helped: therefore my heart greatly rejoiceth and with my song will I praise him', 'My heart is glad and my tongue sings for joy', 'My heart is satisfied and I will never be moved', 'My heart overflows and I will shout for joy', 'a', 'My heart trusted in him, and I am helped: therefore my heart greatly rejoiceth; and with my song will I praise him (Psalm 28:7).'),
-- Adults
('Psalms', 28, 'adults', 1, 'What is the structural movement of Psalm 28 from petition to praise?', 'The psalm remains in petition throughout', 'Verses 1-5 are intense petition; verses 6-9 are sudden praise — the shift indicates the psalmist''s prayer has been heard (or received as heard by faith)', 'The psalm is entirely praise', 'The praise is placed at the beginning', 'a', 'Psalm 28 moves from urgent petition (vv.1-5) to sudden praise (vv.6-9): "Blessed be the LORD, because he hath heard the voice of my supplications" (Psalm 28:6).'),
('Psalms', 28, 'adults', 2, 'What does "the holy oracle" (devir) in Psalm 28:2 refer to?', 'A prophetic utterance', 'The inner sanctuary of the temple — the Holy of Holies where God''s presence dwelt above the ark', 'A special prayer room', 'The outer court of the temple', 'a', 'I lift up my hands toward thy holy oracle (Psalm 28:2) — devir refers to the inner sanctuary, the Holy of Holies, the most holy chamber of the temple.'),
('Psalms', 28, 'adults', 3, 'Why does David distinguish between himself and "the workers of iniquity" who speak peace while planning mischief in Psalm 28:3?', 'He is asserting moral superiority', 'He is establishing his innocence as part of his appeal — he has not acted with duplicity as they have, making his cry for deliverance just', 'He is warning others about false friends', 'He is making a sociological observation', 'a', 'Draw me not away with the wicked...which speak peace to their neighbours, but mischief is in their hearts (Psalm 28:3) — David''s integrity contrasts with their duplicity, forming his claim to divine help.'),
('Psalms', 28, 'adults', 4, 'What does "feed them also, and lift them up for ever" in Psalm 28:9 reveal about David''s understanding of his royal function?', 'David sees himself as a farmer', 'The king''s role is pastoral — to feed (shepherd) and lift up (carry) God''s people — reflecting the shepherd-king theology of the ancient Near East', 'David is asking God to feed his army', 'The verse is about agricultural abundance', 'a', 'Feed them also, and lift them up for ever (Psalm 28:9) — the language is pastoral; the king''s divinely appointed role is to shepherd and sustain God''s flock.'),
('Psalms', 28, 'adults', 5, 'What is the theological significance of "Blessed be the LORD, because he hath heard the voice of my supplications" in Psalm 28:6?', 'It is premature thanksgiving before answered prayer', 'It is a confident declaration of faith — the psalmist blesses God for answered prayer, expressing certainty that the petition has been received', 'It is a liturgical formula unrelated to David''s specific prayer', 'It contradicts the preceding lament', 'a', 'Blessed be the LORD, because he hath heard the voice of my supplications (Psalm 28:6) — this sudden shift to blessing indicates the psalmist''s confident assurance that God has heard.'),
('Psalms', 28, 'adults', 6, 'What does the juxtaposition of "saving strength of his anointed" and "bless thine inheritance" in Psalm 28:8-9 connect?', 'Military strength and agricultural blessing', 'The king (anointed) and the people (inheritance) — both are objects of God''s saving care, showing that the king''s welfare and the people''s welfare are inseparable', 'The temple and the palace', 'Prayer and sacrifice', 'a', 'The LORD is the saving strength of his anointed (king) — save thy people and bless thine inheritance (people) (Psalm 28:8-9) — king and people together are God''s concern.'),
('Psalms', 28, 'adults', 7, 'What is the danger of God being "silent" in Psalm 28:1, and what does this reveal about the nature of divine communication?', 'God''s silence means he does not exist', 'Divine silence is equivalent to abandonment — God''s active response to prayer is constitutive of the relationship; his silence disrupts the covenantal bond', 'Silence means God is pleased', 'Silence means David needs to pray louder', 'a', 'Be not silent to me: lest I become like them that go down into the pit (Psalm 28:1) — God''s silence would be indistinguishable from absence, destroying the covenantal relationship.'),
('Psalms', 28, 'adults', 8, 'How does the retribution language of Psalm 28:4 ("give them according to their deeds") relate to the New Testament''s principle of divine justice?', 'It contradicts the New Testament''s grace', 'It reflects the biblical principle that God repays according to works (Romans 2:6), a principle consistent with both Testaments as it pertains to the final judgment', 'It shows the Old Testament is inferior', 'It applies only to Israel''s enemies', 'a', 'Give them according to their deeds (Psalm 28:4) — consistent with Romans 2:6: "God will render to every man according to his deeds" — the principle of moral accountability spans both Testaments.');

-- ═══ Psalms Chapter 29 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 29, 'kids', 1, 'What does Psalm 29 call the voice of the LORD?', 'Powerful and full of majesty', 'Sweet and gentle', 'Quiet and still', 'Loud and frightening', 'a', 'The voice of the LORD is powerful; the voice of the LORD is full of majesty (Psalm 29:4).'),
('Psalms', 29, 'kids', 2, 'How many times is "the voice of the LORD" mentioned in Psalm 29?', 'Seven times', 'Three times', 'Five times', 'Ten times', 'a', '"The voice of the LORD" appears seven times in Psalm 29 (vv.3-9), representing the completeness of God''s powerful voice.'),
('Psalms', 29, 'kids', 3, 'What does the LORD sit upon in Psalm 29?', 'The flood', 'His holy mountain', 'The ark of the covenant', 'His great throne', 'a', 'The LORD sitteth upon the flood; yea, the LORD sitteth King for ever (Psalm 29:10).'),
-- Teens
('Psalms', 29, 'teens', 1, 'Who is called to give glory and strength to the LORD in Psalm 29:1?', 'The mighty — O ye mighty', 'The kings of the earth', 'The sons of Israel', 'The priests and Levites', 'a', 'Give unto the LORD, O ye mighty, give unto the LORD glory and strength (Psalm 29:1).'),
('Psalms', 29, 'teens', 2, 'What does the voice of the LORD do to the cedars of Lebanon in Psalm 29?', 'It breaketh the cedars of Lebanon', 'It bends the cedars of Lebanon', 'It topples the cedars of Lebanon', 'It fills the cedars of Lebanon', 'a', 'The voice of the LORD breaketh the cedars; yea, the LORD breaketh the cedars of Lebanon (Psalm 29:5).'),
('Psalms', 29, 'teens', 3, 'What do the inhabitants of the temple say in Psalm 29:9?', 'Glory', 'Hallelujah', 'Amen', 'Holy', 'a', 'And in his temple doth every one speak of his glory (Psalm 29:9).'),
('Psalms', 29, 'teens', 4, 'What does the LORD give to his people in Psalm 29:11?', 'Strength and peace', 'Wisdom and grace', 'Victory and joy', 'Land and abundance', 'a', 'The LORD will give strength unto his people; the LORD will bless his people with peace (Psalm 29:11).'),
('Psalms', 29, 'teens', 5, 'What does the voice of the LORD make the wilderness do in Psalm 29?', 'The voice of the LORD shaketh the wilderness of Kadesh', 'The voice of the LORD fills the wilderness', 'The voice of the LORD enlightens the wilderness', 'The voice of the LORD waters the wilderness', 'a', 'The voice of the LORD shaketh the wilderness; the LORD shaketh the wilderness of Kadesh (Psalm 29:8).'),
-- Adults
('Psalms', 29, 'adults', 1, 'Psalm 29 has what relationship to ancient Canaanite Baal hymns, and what is the theological significance?', 'It is completely original with no parallels', 'It uses similar storm-theophany imagery but attributes all power to YHWH, not Baal — a polemic claiming that what Canaanite mythology attributed to Baal belongs exclusively to Israel''s God', 'It was written in response to Canaanite worship to condemn Israel', 'It borrows Canaanite mythology uncritically', 'a', 'Psalm 29 uses storm imagery similar to Canaanite Baal hymns but deliberately attributes all power to YHWH — a polemic demythologizing Baal and asserting YHWH''s sole sovereignty.'),
('Psalms', 29, 'adults', 2, 'What is the significance of the voice of the LORD appearing exactly seven times in Psalm 29?', 'It is a coincidence of poetic style', 'Seven represents completeness in Hebrew — God''s voice completely pervades creation, exercising total sovereign power over all natural forces', 'Seven was a sacred number in Canaan', 'Seven refers to the seven days of creation', 'a', 'The sevenfold "voice of the LORD" (Psalm 29:3-9) — seven being the number of completeness — expresses the total, all-pervading power of God''s word through creation.'),
('Psalms', 29, 'adults', 3, 'What does the command to "give unto the LORD glory and strength" to the "mighty" (bene Elim) in Psalm 29:1 imply?', 'Human warriors are addressed', 'The heavenly court — "sons of the divine beings/gods" (angelic beings) — are commanded to worship YHWH, asserting his supremacy over all divine beings', 'The priesthood is addressed', 'The nations are commanded to convert', 'a', 'Give unto the LORD, O ye mighty (bene Elim — sons of gods/divine beings) (Psalm 29:1) — the heavenly court of divine beings is summoned to acknowledge YHWH''s supreme glory.'),
('Psalms', 29, 'adults', 4, 'What does the LORD''s sitting "upon the flood" (mabbul) in Psalm 29:10 specifically recall?', 'The Red Sea crossing', 'The Noahic flood (mabbul is the specific Hebrew word used only for Noah''s flood) — asserting God''s eternal sovereignty over the most catastrophic natural disaster in history', 'The Jordan crossing', 'A general reference to storm waters', 'a', 'The LORD sitteth upon the flood (mabbul) (Psalm 29:10) — mabbul is the specific word for Noah''s catastrophic flood (Genesis 6-8), asserting YHWH''s eternal throne above even the greatest cosmic disaster.'),
('Psalms', 29, 'adults', 5, 'How does Psalm 29 move from cosmic theophany to pastoral blessing, and what does this reveal about God''s character?', 'The pastoral blessing is unconnected to the theophany', 'The same God whose voice shatters cedars and shakes the wilderness gives strength and peace to his people — cosmic power channeled into tender pastoral care', 'The blessing is for the angels only', 'The cosmic events are metaphors for political events', 'a', 'The voice that breaks cedars and shakes the wilderness (vv.5-8) is the same LORD who gives strength and peace to his people (v.11) — cosmic majesty and pastoral tenderness united.'),
('Psalms', 29, 'adults', 6, 'What does "in his temple doth every one speak of his glory" in Psalm 29:9 reveal about the purpose of corporate worship?', 'Temple worship is mandatory', 'The entire created order''s response to God''s power (vv.3-9) culminates in the temple congregation''s declaration of glory — worship is the appropriate human response to divine theophany', 'The temple is more holy than creation', 'Only the clergy declare God''s glory', 'a', 'In his temple doth every one speak of his glory (Psalm 29:9) — the temple congregation''s worship is the human echo of creation''s testimony to YHWH''s power throughout the psalm.'),
('Psalms', 29, 'adults', 7, 'What is the theological structure of Psalm 29: address (vv.1-2), theophany (vv.3-9), enthronement (v.10), and blessing (v.11)?', 'The structure is random', 'The psalm moves from summons to worship → God''s voice in storm → God enthroned → God''s blessing: a complete theological narrative from creation''s praise to the covenant community''s peace', 'The structure is a lament', 'The structure belongs to wisdom literature', 'a', 'Psalm 29 follows: summons to heavenly court (vv.1-2) → sevenfold theophany (vv.3-9) → eternal enthronement (v.10) → blessing of God''s people (v.11) — a complete theological arc.'),
('Psalms', 29, 'adults', 8, 'How does the closing blessing "the LORD will bless his people with peace" (shalom) in Psalm 29:11 reframe all the thunderous power in the psalm?', 'It contradicts the power imagery', 'It reveals that God''s terrifying cosmic power exists for the purpose of shalom — the welfare, wholeness, and flourishing of his covenant people', 'Peace is an afterthought to power', 'The blessing is for future generations only', 'a', 'The LORD will bless his people with peace (Psalm 29:11) — all the thunderous power of vv.3-10 is channeled toward shalom (wholeness/flourishing) for the covenant people.');

-- ═══ Psalms Chapter 30 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Psalms', 30, 'kids', 1, 'What does Psalm 30 say about weeping and joy?', 'Weeping may endure for a night, but joy cometh in the morning', 'Weeping shall turn to laughter', 'Weeping is only for a moment', 'Weeping leads to great blessing', 'a', 'Weeping may endure for a night, but joy cometh in the morning (Psalm 30:5).'),
('Psalms', 30, 'kids', 2, 'What did God do for David when his enemies could not rejoice over him?', 'Thou hast lifted me up', 'Thou hast saved me from danger', 'Thou hast given me victory', 'Thou hast healed my sickness', 'a', 'I will extol thee, O LORD; for thou hast lifted me up, and hast not made my foes to rejoice over me (Psalm 30:1).'),
('Psalms', 30, 'kids', 3, 'What does God turn into dancing in Psalm 30?', 'My mourning', 'My sadness', 'My tears', 'My sorrow', 'a', 'Thou hast turned for me my mourning into dancing (Psalm 30:11).'),
-- Teens
('Psalms', 30, 'teens', 1, 'What is the superscription of Psalm 30 about?', 'A Song at the dedication of the house of David', 'A prayer in time of sickness', 'A song of victory after battle', 'A thanksgiving for deliverance from enemies', 'a', 'The superscription reads: "A Psalm and Song at the dedication of the house of David."'),
('Psalms', 30, 'teens', 2, 'What does David say God prevented him from when he cried to him in Psalm 30?', 'Thou hast healed me and not let my foes rejoice over me', 'Thou hast kept me from falling into the pit', 'Thou hast saved me from the sword of mine enemies', 'Thou hast protected me from the fire of my enemies', 'a', 'O LORD my God, I cried unto thee, and thou hast healed me. O LORD, thou hast brought up my soul from the grave: thou hast kept me alive (Psalm 30:2-3).'),
('Psalms', 30, 'teens', 3, 'How long does God''s anger last compared to his favour according to Psalm 30:5?', 'His anger is but for a moment; in his favour is life', 'His anger lasts one year; his favour lasts forever', 'His anger endures a day; his favour endures a week', 'His anger passes in a night; his favour shines in the morning', 'a', 'For his anger endureth but a moment; in his favour is life: weeping may endure for a night, but joy cometh in the morning (Psalm 30:5).'),
('Psalms', 30, 'teens', 4, 'What did David say in his prosperity that made him overconfident in Psalm 30?', 'I shall never be moved', 'I have more than enough', 'No enemy can reach me', 'I am the greatest of kings', 'a', 'And in my prosperity I said, I shall never be moved (Psalm 30:6).'),
('Psalms', 30, 'teens', 5, 'What does David say God has clothed him with instead of sackcloth in Psalm 30:11?', 'Gladness', 'Joy', 'Righteousness', 'Honour', 'a', 'Thou hast turned for me my mourning into dancing: thou hast put off my sackcloth, and girded me with gladness (Psalm 30:11).'),
-- Adults
('Psalms', 30, 'adults', 1, 'What is the superscription "A Psalm and Song at the dedication of the house of David" and how has this been interpreted historically?', 'The psalm was written by Solomon for the temple', 'It may refer to dedication of David''s palace (2 Samuel 5:11), or was later adapted for use at Hanukkah — the re-dedication of the temple after Maccabean victory', 'It refers to the ark being brought to Zion', 'It was written for the dedication of a private home', 'a', 'The superscription (Psalm 30:1) has been interpreted as referring to David''s house dedication (2 Samuel 5) or adapted for Hanukkah (temple re-dedication), hence its use in Jewish liturgy for Hanukkah.'),
('Psalms', 30, 'adults', 2, 'What does "thou hast brought up my soul from the grave" (she''ol) in Psalm 30:3 indicate about the nature of the crisis?', 'A literal death and resurrection', 'A near-death illness from which David was miraculously recovered — she''ol describes the extreme danger from which God rescued him', 'A spiritual descent into sin', 'A metaphor for deep sadness', 'a', 'Thou hast brought up my soul from the grave (she''ol) (Psalm 30:3) — the language of descent into she''ol indicates a near-fatal illness from which God gave recovery.'),
('Psalms', 30, 'adults', 3, 'What is the theological danger exposed in David''s confession "in my prosperity I said, I shall never be moved" in Psalm 30:6?', 'Prosperity itself is sinful', 'Prosperity can produce a self-reliant independence from God — the very stability God provides can become a source of forgetting God', 'David was being falsely modest', 'David was expressing appropriate confidence', 'a', 'In my prosperity I said, I shall never be moved (Psalm 30:6) — prosperity bred self-sufficiency; when God hid his face David was suddenly troubled, exposing the fragility of human confidence.'),
('Psalms', 30, 'adults', 4, 'What argument does David use in Psalm 30:9 to motivate God to heal him, similar to Psalm 6:5?', 'His righteousness deserves healing', 'What profit is there in my blood if I go down to the pit? The dead cannot praise God — his life serves God''s glory', 'His enemies will mock God if he dies', 'His family will suffer without him', 'a', 'What profit is there in my blood, when I go down to the pit? Shall the dust praise thee? shall it declare thy truth? (Psalm 30:9) — David argues his living praise serves God''s purposes (cf. Psalm 6:5).'),
('Psalms', 30, 'adults', 5, 'What is the significance of the contrast between "a moment" and "a night" in Psalm 30:5 regarding God''s anger and favour?', 'God''s anger is eternal', 'God''s anger is momentary and temporary; his favour constitutes life itself — the fundamental asymmetry shows God''s love is his dominant disposition toward his people', 'Anger and favour are equal in duration', 'This is a general observation about human emotions', 'a', 'His anger endureth but a moment; in his favour is life (Psalm 30:5) — anger is quantified as a moment; favour is equated with life itself — a massive asymmetry revealing God''s character.'),
('Psalms', 30, 'adults', 6, 'What does the transformation from sackcloth to gladness in Psalm 30:11 symbolize in the context of ancient mourning customs?', 'A change of clothing only', 'Sackcloth was the garment of grief and penitence; gladness is the eschatological restoration — God reverses every sign of mourning and replaces it with celebration', 'A priestly investiture ceremony', 'David is describing a literal event of changing clothes', 'a', 'Thou hast put off my sackcloth, and girded me with gladness (Psalm 30:11) — sackcloth represented mourning; God''s reversal of sackcloth to gladness is a complete transformation of status.'),
('Psalms', 30, 'adults', 7, 'How does "weeping may endure for a night, but joy cometh in the morning" in Psalm 30:5 function as a theodicy?', 'It denies that suffering is real', 'It does not minimize suffering (weeping is real) but asserts its temporality — God''s redemptive morning is guaranteed to follow every night of tears', 'It promises immediate relief', 'It teaches that joy always follows weeping the very next morning', 'a', 'Weeping may endure for a night, but joy cometh in the morning (Psalm 30:5) — a theodicy that affirms suffering''s reality while insisting on its temporal limit within God''s redemptive purposes.'),
('Psalms', 30, 'adults', 8, 'What does the final purpose clause "to the end that my glory may sing praise to thee, and not be silent" in Psalm 30:12 reveal about the ultimate purpose of deliverance?', 'God delivers for David''s personal benefit', 'God''s deliverance has as its goal the praise of the delivered — deliverance creates worshippers, and worship is the ultimate purpose of redemption', 'God delivers to prove his power to enemies', 'God delivers to show David''s worthiness', 'a', 'To the end that my glory may sing praise to thee, and not be silent (Psalm 30:12) — the purpose of divine rescue is the creation of praise: deliverance exists for worship.');


